-- Poems batch 231
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('99baaa7f-f846-49b7-add6-37ea2987426c','江湖偉觀山亭二首  其一','葉茵','宋','宋诗','song-poetry','','[]','結束虛亭近太清，山光水影互逢迎。',32,'全唐诗/poet.song.211000.json','["結束虛亭近太清，山光水影互逢迎。", "人心祗覺山多險，幾箇人心水樣平。"]'),
('c36bea8f-b265-438f-89ea-29127d57c9a7','江湖偉觀山亭二首  其二','葉茵','宋','宋诗','song-poetry','','[]','軟紅塵外聳嵯峩，題品先曾屬老坡。',32,'全唐诗/poet.song.211000.json','["軟紅塵外聳嵯峩，題品先曾屬老坡。", "立脚愈高天愈闊，靜看舟楫駕風波。"]'),
('33c5edf1-0637-4c9a-a70e-89f34ac63403','次七夕游松江韻','葉茵','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','謫仙歌洞庭，坡翁賦赤壁。',192,'全唐诗/poet.song.211000.json','["謫仙歌洞庭，坡翁賦赤壁。", "逢時汗漫游，元不計何夕。", "慨慷晞英豪，老大謾悽惻。", "矧茲笠澤區，萬頃混空碧。", "一葦縱所如，卧虹控秋色。", "雲軿駕雙星，銀潢幾經歷。", "柳州乞巧文，我欲爲己易。", "邂逅竹林賢，胸次小八極。", "氣勝棋聲高，量寬酒杯窄。", "載笑輕公侯，一閒抵金璧。", "多謝簡齋孫，遺詩話平昔。", "二雛掖吾旁，對景亦自得。", "髣髴真率會，相與鄙肉食。", "駐睇芙蕖邊，擬卜子雲宅。", "清風繼三高，名利焉能役。", "因誇江上人，有此坐中客。"]'),
('a845fac1-e262-48ed-87ac-40d115dc1da6','試問','葉茵','宋','宋诗','song-poetry','','[]','在在江湖蘆葦，家家楊柳樓臺。',28,'全唐诗/poet.song.211000.json','["在在江湖蘆葦，家家楊柳樓臺。", "試問燕鴻心事，爲誰飛去飛來。"]'),
('cdf80b09-f1d5-4eed-925d-c02aefd67743','己酉九日次靖節是歲是日韻','葉茵','宋','宋诗','song-poetry','','[]','采采籬下菊，熙熙白首交。',96,'全唐诗/poet.song.211000.json','["采采籬下菊，熙熙白首交。", "挈觴酬佳節，先驚蒲柳凋。", "日月不再與，名位空相高。", "巋然龍山青，千古擎丹霄。", "彼美一晉士，長接辭塵勞。", "留錢寄酒家，快飲如沃焦。", "尚友前輩意，兀兀而陶陶。", "且了今日歡，誰能憂來朝。"]'),
('0f0d6325-02fc-4778-b8f3-da5bb59292ec','長相思','葉茵','宋','宋诗','song-poetry','','[]','長相思，情萬折，年少不來春又別。',48,'全唐诗/poet.song.211000.json','["長相思，情萬折，年少不來春又別。", "寶匳香，繡幃月。", "鴻鴈音信稀，鴛鴦魂夢絕。", "尚持百年願，料理丁香結。"]'),
('f7dc4368-2a39-42d4-942d-d3dd2877dcb5','松江','葉茵','宋','宋诗','song-poetry','','[]','占得中吳第一清，蓴鱸里社可鷗盟。',64,'全唐诗/poet.song.211000.json','["占得中吳第一清，蓴鱸里社可鷗盟。", "七層燈火重湖影，千尺闌干兩市聲。", "欵乃歌分長短律，往來帆带古今情。", "三高豈是無名利，祗與時人有重輕。"]'),
('3dc6905a-489b-4b50-97a5-0d40f3f9f805','南明樓','葉茵','宋','宋诗','song-poetry','','[]','重簷敞處受槐薰，掃盡江村雨後雲。',64,'全唐诗/poet.song.211000.json','["重簷敞處受槐薰，掃盡江村雨後雲。", "佛法本無南北異，世情强有晦明分。", "箇中苟住元無住，此外無聞却是聞。", "誰道結樓入已去，牀頭詩版幾朝曛。"]'),
('1bc43195-13fe-4268-a320-ab89a25ecdc8','壺中林壑','葉茵','宋','宋诗','song-poetry','','[]','山下水一泓，山上雲一朵。',24,'全唐诗/poet.song.211000.json','["山下水一泓，山上雲一朵。", "有塵飛不來，終年風月我。"]'),
('784d68b9-8eb0-4a83-8034-95c4e897a083','柿葉','葉茵','宋','宋诗','song-poetry','','[]','柿葉紅如染，橫陳几席間。',24,'全唐诗/poet.song.211000.json','["柿葉紅如染，橫陳几席間。", "小題秋樣句，客思滿江山。"]'),
('00c0eee4-2537-4740-ac44-4d390c062773','道院','葉茵','宋','宋诗','song-poetry','','[]','菰蒲衛竹居，適意在江湖。',48,'全唐诗/poet.song.211000.json','["菰蒲衛竹居，適意在江湖。", "富貴諸公有，清閒舉世無。", "四時盤谷序，一景輞川圖。", "何處無芳草，堪嗟楚大夫。"]'),
('c9088da5-b6ca-4a6c-b7d2-ab3a5b573319','旅中','葉茵','宋','宋诗','song-poetry','','[]','節序幾循環，重來秋又殘。',48,'全唐诗/poet.song.211000.json','["節序幾循環，重來秋又殘。", "霜晴生酒熟，風冷夾衣單。", "未羨千鍾祿，寧求一枕安。", "白頭逢歲稔，憂國素心寬。"]'),
('7c0513d7-389b-4774-86fe-8b01ad16d135','寄台守','葉茵','宋','宋诗','song-poetry','','[]','半世困塵埃，煙霞入夢來。',48,'全唐诗/poet.song.211000.json','["半世困塵埃，煙霞入夢來。", "誰能縮地脈，我已思天台。", "城古清雲氣，山靈秀藥材。", "春時穿徑去，郡守莫驚猜。"]'),
('5f0b9976-16d8-49e7-9010-a69a7a62ed98','林和靖祠','葉茵','宋','宋诗','song-poetry','','[]','鶴去山孤草亦荒，旋吟長句謁虛堂。',32,'全唐诗/poet.song.211000.json','["鶴去山孤草亦荒，旋吟長句謁虛堂。", "束芻尚擬人如玉，一朵梅花當瓣香。"]'),
('a403d940-cd05-4257-85cb-3b9724f43ba2','三高祠','葉茵','宋','宋诗','song-poetry','','[]','一爲功成一見幾，一逢叔世老漁磯。',32,'全唐诗/poet.song.211000.json','["一爲功成一見幾，一逢叔世老漁磯。", "後人欲隠求其志，志不因時隠亦非。"]'),
('4b22f0f2-64d1-4a20-a79f-c2a91e17f23a','白牡丹','葉茵','宋','宋诗','song-poetry','','[]','洛陽分種入侯家，魏紫姚黄謾自誇。',32,'全唐诗/poet.song.211000.json','["洛陽分種入侯家，魏紫姚黄謾自誇。", "素質不爲顔色污，看來清得似梅花。"]'),
('5e3aa2ee-2ff0-49e6-a358-01898a69c488','生日對梅口占','葉茵','宋','宋诗','song-poetry','','[]','一生已得半生閒，出入詩篇酒盞間。',64,'全唐诗/poet.song.211000.json','["一生已得半生閒，出入詩篇酒盞間。", "祗把小兒看造化，不妨老子號癡頑。", "幻身且喜無諸恙，靈藥誰能覓大還。", "多謝梅花來薦壽，年年雪裏破春顔。"]'),
('52e5227a-d4d6-4a8e-989d-68950df8a581','次王竹齋韻','葉茵','宋','宋诗','song-poetry','','[]','忘身忘世老方回，適處從教節物催。',64,'全唐诗/poet.song.211000.json','["忘身忘世老方回，適處從教節物催。", "幾日吟情爲熱惱，一天生意趁凉來。", "屋邊花竹時時好，水外軒窗面面開。", "獨有此君同此趣，百年事業兩三杯。"]'),
('3ea266b5-7a0e-4f25-aa43-03df0aff6dd1','漁家行','葉茵','宋','宋诗','song-poetry','','[]','湖濱江滸疎疎村，村村漁家人子孫。',140,'全唐诗/poet.song.211000.json','["湖濱江滸疎疎村，村村漁家人子孫。", "爲魚不管波浪惡，出未天明歸黄昏。", "得來魚可數，妻兒相對語。", "甕頭有齏熟，鍋中無米煮。", "昔日魚多江湖寬，今日江湖半屬官。", "釣筒釣車謾百尺，團罟帆罟空多般。", "蓋蓑臘雪楊柳岸，籠手西風蘆荻灘。", "差差舴艋千百隻，盡向其中仰衣食。", "幾謀脫離江湖歸犂鉏，似聞歲惡農家尤費力。"]'),
('5647bf1d-0cab-4f10-96b8-5a0e593a68be','石湖','葉茵','宋','宋诗','song-poetry','','[]','千古湖山人物，百年翰墨文章。',28,'全唐诗/poet.song.211000.json','["千古湖山人物，百年翰墨文章。", "寂寞梅花開處，一尊自酹寒香。"]'),
('37dd3c45-7775-4f88-bb82-703579a1d803','蠶婦吟二首  其一','葉茵','宋','宋诗','song-poetry','','[]','九日三眠火力齊，五朝又報四眠時。',32,'全唐诗/poet.song.211000.json','["九日三眠火力齊，五朝又報四眠時。", "辛勤一月方能繭，繰得成絲却賣絲。"]'),
('ef728573-e1ba-467c-9f7d-221a99233f19','蠶婦吟二首  其二','葉茵','宋','宋诗','song-poetry','','[]','掃下烏兒毛樣細，滿箱桑葉翦青柔。',32,'全唐诗/poet.song.211000.json','["掃下烏兒毛樣細，滿箱桑葉翦青柔。", "大姑不似三姑巧，今歲繰絲兩倍收。"]'),
('3b1f93e4-a93f-4438-bafd-b21cd61fecf3','昭君怨','葉茵','宋','宋诗','song-poetry','','[]','塞上將軍且罷兵，一身萬里自經營。',32,'全唐诗/poet.song.211000.json','["塞上將軍且罷兵，一身萬里自經營。", "將軍歌舞升平日，却調琵琶寄怨聲。"]'),
('903f70d4-155d-479f-aee3-26291738585d','自適','葉茵','宋','宋诗','song-poetry','','[]','澹薄野人心，難教著利名。',48,'全唐诗/poet.song.211000.json','["澹薄野人心，難教著利名。", "重農田舍熟，省事世情生。", "石老旗槍葉，池喧鼓吹聲。", "東風知此樂，飛絮蕩新晴。"]'),
('a79692cb-340a-433a-9306-108ecd2a7c6f','霉後','葉茵','宋','宋诗','song-poetry','','[]','半日斷梅雨，兩山生火雲。',48,'全唐诗/poet.song.211000.json','["半日斷梅雨，兩山生火雲。", "窗明書少蠹，壁潤帳多蚊。", "無計清時暑，何心解世紛。", "追思河朔輩，倚箑對爐熏。"]'),
('ec156ac6-1c7d-4549-91ff-c2122b676e83','垂虹橋','葉茵','宋','宋诗','song-poetry','','[]','何年現采虹，懸足控西東。',48,'全唐诗/poet.song.211000.json','["何年現采虹，懸足控西東。", "兩地煙波隔，一天風月同。", "艣聲摇鴈柱，簷影覆龍宮。", "讎虜曾垂釣，誰收餌虜功。"]'),
('938add3f-2d8b-42c3-aa4d-64eabf435630','意亭','葉茵','宋','宋诗','song-poetry','','[]','泉石聊復爾，杖屨亦偶然。',24,'全唐诗/poet.song.211000.json','["泉石聊復爾，杖屨亦偶然。", "萬化同一適，魚鳶兮天淵。"]'),
('cfd41d08-4073-47a2-8915-da981b1d773a','野雲菴','葉茵','宋','宋诗','song-poetry','','[]','變態分陰晴，悠悠浮太虛。',24,'全唐诗/poet.song.211000.json','["變態分陰晴，悠悠浮太虛。", "冥與此心契，時哉道卷舒。"]'),
('d764b1af-8e88-4305-b2b6-05a679518606','鶴隴','葉茵','宋','宋诗','song-poetry','','[]','一隴以鶴名，疑是終南徑。',24,'全唐诗/poet.song.211000.json','["一隴以鶴名，疑是終南徑。", "山靈無獻嘲，出處由來定。"]'),
('a7812400-554d-48eb-a0af-5f9d6106d309','雪磴','葉茵','宋','宋诗','song-poetry','','[]','不記門前路，門前一尺深。',24,'全唐诗/poet.song.211000.json','["不記門前路，門前一尺深。", "梅花如有語，參透老逋心。"]'),
('7b58a1b1-5b3a-4da9-8466-886f2123ba63','槃磵','葉茵','宋','宋诗','song-poetry','','[]','盤旋山水間，隠者固所樂。',24,'全唐诗/poet.song.211000.json','["盤旋山水間，隠者固所樂。", "寐寤獨言時，𤱶畝心猶昨。"]'),
('4d86dd44-e849-4f03-ba99-e10721821e5c','耐久交','葉茵','宋','宋诗','song-poetry','','[]','彼哉市道交，出語指天日。',24,'全唐诗/poet.song.211000.json','["彼哉市道交，出語指天日。", "未逢魏與裴，三歎扁斯石。"]'),
('7fef7bf3-aef9-466e-b3ed-0913f61ed938','意行橋','葉茵','宋','宋诗','song-poetry','','[]','枯槎浸清溪，飄飄野雲度。',24,'全唐诗/poet.song.211000.json','["枯槎浸清溪，飄飄野雲度。", "徘徊復徘徊，撚髭未成句。"]'),
('fdcb7eff-b7be-4aa3-ba03-ed499f346ce4','次游法喜寺韻','葉茵','宋','宋诗','song-poetry','','[]','招提四百載，不與世劫俱。',168,'全唐诗/poet.song.211000.json','["招提四百載，不與世劫俱。", "松陵拱空覺，柏香祠真如。", "時秋兆嫩凉，揖客登其廬。", "廊邃碑篆剝，閣迥鐘聲疎。", "中有白足侶，光現摩尼珠。", "勘問點頭石，奔走觀心狐。", "坐我六和室，風回晴窗虛。", "棋枰迭勝負，譁音發酒餘。", "飽分蔬筍供，似可山林居。", "同是百年客，得此一日娛。", "遠社不復見，熟與斯人徒。", "松日簸斜影，麾兒呼移厨。", "駕流來鱸鄉，野雲黏菰蒲。", "客散漁火稀，冉冉吟篷孤。"]'),
('608aee36-c433-4b54-9533-fbc02c73394f','次韻','葉茵','宋','宋诗','song-poetry','','[]','枯坐如僧欠鉢單，年來夢不赴槐安。',64,'全唐诗/poet.song.211000.json','["枯坐如僧欠鉢單，年來夢不赴槐安。", "稀行種竹容風入，大字鈔書就月看。", "爲有故人同冷淡，非干明主棄孤寒。", "因閒悟得家山趣，堪笑世間行路難。"]'),
('2ea56b4e-0e63-4023-b09d-afc7818fcd1d','次韻二首  其一','葉茵','宋','宋诗','song-poetry','','[]','過牆新竹粉痕黏，蛙閙池塘燕掠簷。',64,'全唐诗/poet.song.211000.json','["過牆新竹粉痕黏，蛙閙池塘燕掠簷。", "自喜江鄉成懶散，從教世界要莊嚴。", "稻秧井井畦千緯，荷葉田田水一匳。", "心事太平風物好，與人無愛亦無嫌。"]'),
('6a30b12f-03d6-4e83-94b3-a8d874001a9f','次韻二首  其二','葉茵','宋','宋诗','song-poetry','','[]','難把來箋向後黏，載持珠玉傍風簷。',64,'全唐诗/poet.song.211000.json','["難把來箋向後黏，載持珠玉傍風簷。", "吟根此性辭平易，學本於經意簡嚴。", "未遜彌明聯石鼎，還嗤韓渥賦香匳。", "陽春政不容人和，自聽巴音亦自嫌。"]'),
('89f4d59a-469b-4ccc-94b2-14f8726d21f2','香匳體五首  其一','葉茵','宋','宋诗','song-poetry','','[]','相思獨向小窗明，試翦春衣趁晚晴。',32,'全唐诗/poet.song.211000.json','["相思獨向小窗明，試翦春衣趁晚晴。", "還覺此情絲樣小，欲裁不斷柰何情。"]'),
('280a6bac-05cb-46ce-9995-c7f677699a1a','香匳體五首  其二','葉茵','宋','宋诗','song-poetry','','[]','雌蝶雄蜂綴杏枝，此時此意妾心知。',32,'全唐诗/poet.song.211000.json','["雌蝶雄蜂綴杏枝，此時此意妾心知。", "等閒繡在香囊上，寄與東風贈所思。"]'),
('270842e8-4b41-4302-9aaf-75759509e5bf','香匳體五首  其三','葉茵','宋','宋诗','song-poetry','','[]','千里相思兩寂寥，東陽應減舊時腰。',32,'全唐诗/poet.song.211000.json','["千里相思兩寂寥，東陽應減舊時腰。", "書中喜有歸來字，携傍紅窗把筆描。"]'),
('0e4697c1-9920-4351-8431-3eb7d59879c2','香匳體五首  其四','葉茵','宋','宋诗','song-poetry','','[]','綠楊紅杏閙牆頭，畫出眉山却带秋。',32,'全唐诗/poet.song.211000.json','["綠楊紅杏閙牆頭，畫出眉山却带秋。", "一行珠簾休捲上，怕春知道有人愁。"]'),
('f234736f-6a18-4147-9ac4-98acfb8fe1c7','香匳體五首  其五','葉茵','宋','宋诗','song-poetry','','[]','倚樓目斷暮江邊，約定歸期夜不眠。',32,'全唐诗/poet.song.211000.json','["倚樓目斷暮江邊，約定歸期夜不眠。", "香篆有煙燈有暈，笑移鍼線向牀前。"]'),
('1c7cf526-a2cb-4cda-b71c-6a417f17e51d','秋感','葉茵','宋','宋诗','song-poetry','','[]','蘋洲起壯風，秋事太怱怱。',48,'全唐诗/poet.song.211000.json','["蘋洲起壯風，秋事太怱怱。", "節候一番別，心期幾處同。", "牛沈苔暈碧，蟹斷蓼拖紅。", "有客愁無柰，人生總客中。"]'),
('5d9cd1fd-7e3e-49d7-9330-4409d5ffc6f0','泊然亭','葉茵','宋','宋诗','song-poetry','','[]','舉世正營營，閒中意味深。',48,'全唐诗/poet.song.211000.json','["舉世正營營，閒中意味深。", "無憂伸足夢，自樂曲肱吟。", "火軟香凝穗，簷虛樹長陰。", "客來難舉似，指水印禪心。"]'),
('e78a84d0-d407-4550-a50d-2ceac73e926e','菊','葉茵','宋','宋诗','song-poetry','','[]','壽客若爲情，風流友麴生。',48,'全唐诗/poet.song.211000.json','["壽客若爲情，風流友麴生。", "殿秋安晚節，爲隠被香名。", "曼衍南陽種，淒涼楚澤英。", "見山應自語，今古幾淵明。"]'),
('e9a6e055-e064-4793-89cf-813991276a56','一萬宗推篷圖','葉茵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','載月船空漾寒綠，掀篷半卧聽漁曲。',96,'全唐诗/poet.song.211000.json','["載月船空漾寒綠，掀篷半卧聽漁曲。", "誰家留連萬玉妃，羞露腰肢和面目。", "有緣竊見駝酥胸，靈堅習習生香風。", "剡溪藤下路如掌，憶在西湖煙雨中。", "迦葉相迎開笑口，湯休謝晝幾搔首。", "世間不盡有餘機，除却逃禪人解不。"]'),
('6d1b0b8e-3e28-48f3-afee-c5cf09e5736a','晚春','葉茵','宋','宋诗','song-poetry','','[]','年少逢春不惜春，惜春還是白頭人。',64,'全唐诗/poet.song.211000.json','["年少逢春不惜春，惜春還是白頭人。", "飛花入坐兒曹舞，細草蒙階醉後裀。", "未羨食前羅五鼎，靜看簷隙走雙輪。", "此心已與堯夫似，同爲清時作幸民。"]'),
('1a1a1dac-db14-473c-ae02-40f06dd32d8a','用東坡韻賀可山得子','葉茵','宋','宋诗','song-poetry','','[]','祥光一夜照鄉閭，遲曉鄰翁毓鳳雛。',64,'全唐诗/poet.song.211000.json','["祥光一夜照鄉閭，遲曉鄰翁毓鳳雛。", "舉坐已誇沾玉果，傳家應不負詩書。", "生時恰恰逢秋半，長日駸駸課夜餘。", "自顧阿戎愚且魯，提孩敢說巧相如。"]'),
('6b916ae9-1b2f-4fd0-8a69-a733bd24b275','再韻賀可山新生彌月','葉茵','宋','宋诗','song-poetry','','[]','人誇旌表舊門閭，梅長新枝鶴長雛。',64,'全唐诗/poet.song.211000.json','["人誇旌表舊門閭，梅長新枝鶴長雛。", "八葉可提和靖印，十箱須讀阿宜書。", "誕彌厥月生無害，積善之家慶有餘。", "準擬一饕湯餠供，柰何逢疾似相如。"]'),
('82c38c11-a463-420d-a563-8d60ad660078','春寒','葉茵','宋','宋诗','song-poetry','','[]','寒禁蕨芽拳尚小，雨緘茶觜舌無香。',32,'全唐诗/poet.song.211000.json','["寒禁蕨芽拳尚小，雨緘茶觜舌無香。", "山翁不信春光老，祗道儂家未種秧。"]'),
('ae7c76f6-bac4-4af9-a31b-47f457da656e','次韻','葉茵','宋','宋诗','song-poetry','','[]','世間何事不何樓，莫爲何樓苦苦愁。',32,'全唐诗/poet.song.211000.json','["世間何事不何樓，莫爲何樓苦苦愁。", "貴客五更馳寶勒，海翁終日對沙鷗。"]'),
('fe81ba5c-f279-45d3-9ee1-1c38eec6a4e6','次范無外孫花翁游法喜寺韻二首  其一','葉茵','宋','宋诗','song-poetry','','[]','兩橋橫處放潮回，橋外花村漲晚埃。',32,'全唐诗/poet.song.211000.json','["兩橋橫處放潮回，橋外花村漲晚埃。", "省事老禪門閉早，焚香對月禮如來。"]'),
('20721b74-bf65-4edd-b495-55ddc5cf8401','次范無外孫花翁游法喜寺韻二首  其二','葉茵','宋','宋诗','song-poetry','','[]','江流環合路紆回，香火千年地少埃。',32,'全唐诗/poet.song.211000.json','["江流環合路紆回，香火千年地少埃。", "佛法本從方寸起，逢人剛道自西來。"]'),
('b57be924-4e99-4719-83c6-64d5270b27ac','簡閒雲','葉茵','宋','宋诗','song-poetry','','[]','咫尺不相見，隔江應見難。',48,'全唐诗/poet.song.211000.json','["咫尺不相見，隔江應見難。", "有孤今雨約，轉覺暮雲寒。", "是處蓮堪社，何時芋共餐。", "相思正無頼，鵲喜近闌干。"]'),
('c3e014ab-fa14-469f-be58-3c1bbb30f7ff','二子讀詩戲成','葉茵','宋','宋诗','song-poetry','','[]','翁琢五七字，兒親三百篇。',48,'全唐诗/poet.song.211000.json','["翁琢五七字，兒親三百篇。", "要知皆學力，未可以言傳。", "得處有深淺，覺來無後先。", "殊途歸一轍，飛躍自魚鳶。"]'),
('705c1d24-d345-4a57-959e-8de51ed4f087','舟行次韻二首  其一','葉茵','宋','宋诗','song-poetry','','[]','相逢隠者流，同是五湖舟。',48,'全唐诗/poet.song.211000.json','["相逢隠者流，同是五湖舟。", "爲老銘三住，因閒話四休。", "黄沙明野渡，畫角咽譙樓。", "已踐登山約，煎茶更少留。"]'),
('4a2728be-c17b-4300-9350-3e9e8405f699','舟行次韻二首  其二','葉茵','宋','宋诗','song-poetry','','[]','河漢浄如流，枯槎便可舟。',48,'全唐诗/poet.song.211000.json','["河漢浄如流，枯槎便可舟。", "掉頭諸事懶，彈指半生休。", "撼竹風疑雨，依山屋當樓。", "此游情味好，應不待苛留。"]'),
('72c850ef-bf55-4ee5-b4e5-0f05939c3fa8','自釋','葉茵','宋','宋诗','song-poetry','','[]','繁紅妒紫絢前林，杖策來棲花下陰。',64,'全唐诗/poet.song.211000.json','["繁紅妒紫絢前林，杖策來棲花下陰。", "休道游情難似昔，可能他日尚如今。", "乍晴澗曲縈流水，未曉庭臯調野禽。", "畢竟老天憐老子，幽閒斷送一生心。"]'),
('78ddd38c-2896-4ad6-a305-09827baf5e5f','寄越倅','葉茵','宋','宋诗','song-poetry','','[]','幾欲扁舟載雪來，可人風月相蓬萊。',64,'全唐诗/poet.song.211000.json','["幾欲扁舟載雪來，可人風月相蓬萊。", "因思渭北吟春樹，消得江南寄早梅。", "應接山川公事省，主盟觴詠曠懷開。", "何當身與浮雲似，朝暮飄飄往又回。"]'),
('fff8317c-0a71-4b5b-a9e3-aca2cb8b6124','林可山薦毛監場寫梅','葉茵','宋','宋诗','song-poetry','','[]','漢庭延壽丹青名，解使蛾眉休甲兵。',64,'全唐诗/poet.song.211000.json','["漢庭延壽丹青名，解使蛾眉休甲兵。", "之子懶作迺翁畫，直向梅花苦用情。", "筆端不復污脂粉，臨成天地無邊清。", "更將此意語君復，歲寒應與孤山盟。"]'),
('d706604f-7642-468d-b5a2-9945ce1c2fe3','贈立虛舟','葉茵','宋','宋诗','song-poetry','','[]','植杖踞磐石，邂逅蹌踉師。',108,'全唐诗/poet.song.211000.json','["植杖踞磐石，邂逅蹌踉師。", "叩之何方來，偃息招黿池。", "杭蘆訪蓴江，臨流弄漣漪。", "春老芳事歇，風前蒲差差。", "人景與心會，聊以聲吾伊。", "作茗話今昔，幾逢夜壑移。", "達哉無住想，遥與蒙莊期。", "名似囿於物，非莊所能知。", "三語三不答，出門賓晴曦。"]'),
('b070dbc7-465f-4dc6-85e5-74bb4303d265','舟中即事','葉茵','宋','宋诗','song-poetry','','[]','一岸茭蘆何處村，小舟蕩漾日黄昏。',32,'全唐诗/poet.song.211000.json','["一岸茭蘆何處村，小舟蕩漾日黄昏。", "棲鴉散亂風驚柳，漁火清熒人倚門。"]'),
('969f209a-fa08-4d79-b6d4-537482150b4b','次韻','葉茵','宋','宋诗','song-poetry','','[]','看月過天中，貪幽臭味同。',48,'全唐诗/poet.song.211000.json','["看月過天中，貪幽臭味同。", "竹光延野碧，燈影染窗紅。", "聽客談時務，呼兒誦國風。", "還思浮世事，到底是匆匆。"]'),
('aa4fabf3-14a4-4e2c-9663-020bd1420306','餞族姪入幕','葉茵','宋','宋诗','song-poetry','','[]','衝寒謁子陵，好挹釣臺清。',48,'全唐诗/poet.song.211000.json','["衝寒謁子陵，好挹釣臺清。", "若遇多梅處，須寬半日程。", "少年先器識，實地作功名。", "太守賢明甚，當如事父兄。"]'),
('c4a89d8f-ffb8-46bc-a936-eea7bfb39e55','道院偶成','葉茵','宋','宋诗','song-poetry','','[]','把茅爲屋竹爲城，柏子香銷道氣生。',64,'全唐诗/poet.song.211000.json','["把茅爲屋竹爲城，柏子香銷道氣生。", "九十春光花一片，萬千心事雨三更。", "連村鼉鼓相高下，斷浦漁燈半滅明。", "閉戶和衣尋小榻，夢回猶聽讀書聲。"]'),
('d747e505-45d1-4d83-a910-4eb469ca2ae0','邑宰劭農','葉茵','宋','宋诗','song-poetry','','[]','雙鳬小駐柳邊洲，豈是花時作勝游。',64,'全唐诗/poet.song.211000.json','["雙鳬小駐柳邊洲，豈是花時作勝游。", "著意勸民躬耒耜，終朝把酒話田疇。", "三年兩下車塵拜，九客同爲野景留。", "桃李成陰春欲去，寸心耿耿夕陽舟。"]'),
('dad3f5d0-f231-41b1-9340-dd7cbff13aed','餞友歸侍','葉茵','宋','宋诗','song-poetry','','[]','閩江閩山相對青，照人肝膽寒如冰。',96,'全唐诗/poet.song.211000.json','["閩江閩山相對青，照人肝膽寒如冰。", "路旁脩松夾古桂，風鼓吟髭月隨袂。", "君有萊衣我獨無，此樂不能與之俱。", "老夫耄矣君年少，喜見功名將遠到。", "歸歟歸歟盍歸歟，長途玉汝千金軀。", "來秋來作廣寒客，相携醉舞紅塵陌。"]'),
('48cfeff4-2ad8-400a-a062-ffc2e821baa3','去去','葉茵','宋','宋诗','song-poetry','','[]','去去扁舟對晚暉，晴和直欲減綿衣。',32,'全唐诗/poet.song.211000.json','["去去扁舟對晚暉，晴和直欲減綿衣。", "風來一陣蘆花過，祗道春殘柳絮飛。"]'),
('5f832b6d-280c-4c1c-9072-51525d18a165','溪上偶成二首  其一','葉茵','宋','宋诗','song-poetry','','[]','霜冷信冬晴，苕溪半日程。',48,'全唐诗/poet.song.211000.json','["霜冷信冬晴，苕溪半日程。", "正篷辭月色，欹枕受松聲。", "漁隠前時約，山謳古樣情。", "料應朝市客，笑我獨爲清。"]'),
('89b2348e-87a9-4f47-87e8-1da578ec5470','溪上偶成二首  其二','葉茵','宋','宋诗','song-poetry','','[]','新月試新晴，扁舟夜奔程。',48,'全唐诗/poet.song.211000.json','["新月試新晴，扁舟夜奔程。", "咿啞千萬意，曖迺兩三聲。", "熟識旅中事，生嫌世上情。", "願爲山簡醉，休問伯夷清。"]'),
('5a822ffa-751b-4d82-96fe-8ad06c74461d','桃花','葉茵','宋','宋诗','song-poetry','','[]','漫山高下武陵花，一片紅酣散晚霞。',32,'全唐诗/poet.song.211000.json','["漫山高下武陵花，一片紅酣散晚霞。", "要識當時秦晉事，隔溪脩竹兩三家。"]'),
('a5fba0e6-83c4-4a34-ad37-5c9e44377375','優鉢羅花','葉茵','宋','宋诗','song-poetry','','[]','九房六瓣瑞天山，香色清嚴入坐寒。',32,'全唐诗/poet.song.211000.json','["九房六瓣瑞天山，香色清嚴入坐寒。", "不悟岑參題品意，後人祗作佛花看。"]'),
('29985a84-0a3a-4fc9-8e29-2667a88c94fc','次韻','葉茵','宋','宋诗','song-poetry','','[]','竹滿園林水滿溝，幽深地位度春秋。',64,'全唐诗/poet.song.211000.json','["竹滿園林水滿溝，幽深地位度春秋。", "坐中不可無侯喜，歌處何須有莫愁。", "別墅簾櫳風颭燕，遠村籉笠雨耕牛。", "老來應物猶强健，多少壯年成夢休。"]'),
('917f9540-883e-4556-8da2-3eb040015239','清暉亭','葉茵','宋','宋诗','song-poetry','','[]','半點囂塵不敢留，晴光野色自浮游。',64,'全唐诗/poet.song.211000.json','["半點囂塵不敢留，晴光野色自浮游。", "一泉走石夜多雨，萬竹圍松風似秋。", "賸喜有詩堪獻佛，從教無骨可封侯。", "上人回施清閒供，蘭芷香中著茗甌。"]'),
('7bfcb976-6143-4dac-ad62-f27189365da2','別曾源一','葉茵','宋','宋诗','song-poetry','','[]','梅邊又上帝王都，柳下俄空處士廬。',64,'全唐诗/poet.song.211000.json','["梅邊又上帝王都，柳下俄空處士廬。", "漢月楚星人去後，淮雲蜀雨事何如。", "東龜不食西征缺，南雁難期北信疎。", "此去叫閽天路直，何時快覩茂陵書。"]'),
('97a96b9a-5f0e-4fdc-bca8-83847ed7b461','洪都宗人則明盛年擇宗子之秀名之曰紹弟書來欲求語則明上侍重親承志篤學恤貧樂善繩繩蟄蟄未可涯也因書昔所賦廣平同系詩一章載賡以慶之','葉茵','宋','宋诗','song-poetry','','[]','善積端如水滌源，源深自可羨來昆。',64,'全唐诗/poet.song.211000.json','["善積端如水滌源，源深自可羨來昆。", "歲當有室詎爲老，意者重闈思弄孫。", "和樂定知江有渚，碩蕃佇見葉流根。", "河南心印元同自，秋幹虷中細討論。"]'),
('b0fb7516-7aa7-4e37-8b41-db69d8038932','耐久交','葉茵','宋','宋诗','song-poetry','','[]','魚水時暫歡，芝蘭近同臭。',24,'全唐诗/poet.song.211000.json','["魚水時暫歡，芝蘭近同臭。", "惟有石丈人，萬古情如舊。"]'),
('e4c043f1-9167-4bb6-90ec-d4e1d2fb8e71','爛柯山','鄭起','宋','宋诗','song-poetry','','[]','春風萬古洞門開，塵世興亡是幾回。',64,'全唐诗/poet.song.211000.json','["春風萬古洞門開，塵世興亡是幾回。", "棋局至今無處覓，樵人于此遇仙來。", "飛梁橫跨丹虹影，絕頂平鋪白玉堆。", "天下紛紛無好著，斜陽下嶺共徘徊。"]'),
('db9c6713-344e-4241-942f-97fd2a4433cc','卜居','鄭起','宋','宋诗','song-poetry','','[]','久欲謀歸力不任，浮雲踪跡謾巢林。',64,'全唐诗/poet.song.211000.json','["久欲謀歸力不任，浮雲踪跡謾巢林。", "功名未入屠龍手，貧賤常懷買鶴心。", "月下開門微雨過，樓頭聞笛二更深。", "世間萬事俱陳迹，空倚西風閲古今。"]'),
('41cff8cc-0d08-445a-9ae0-7dca8d191004','自黄山還途中作','鄭起','宋','宋诗','song-poetry','','[]','屈指還京十日程，每逢歇處問村名。',64,'全唐诗/poet.song.211000.json','["屈指還京十日程，每逢歇處問村名。", "春沙脈脈溪初漲，夜雨垂垂曉又晴。", "山下有人傳虎出，店中炊飯見牛鳴。", "天涯行客無寧日，不及田家業在耕。"]'),
('1e14128a-c506-4c6f-9ebc-ed6e7705f3c3','謁岳王墳','鄭起','宋','宋诗','song-poetry','','[]','我來拜謁岳王墳，松柏蒼蒼上宿雲。',64,'全唐诗/poet.song.211000.json','["我來拜謁岳王墳，松柏蒼蒼上宿雲。", "臣子報君終一死，權奸賣國欲中分。", "鷹揚當日誰能及，雁叫中原不可聞。", "石馬石人山寂寂，英雄于此憶將軍。"]'),
('9dd4b1db-b307-44e8-a6e7-57061fea2df8','次照晦巖韻','鄭起','宋','宋诗','song-poetry','','[]','便騎老虎不須鞍，忍辱仙人出宰官。',64,'全唐诗/poet.song.211000.json','["便騎老虎不須鞍，忍辱仙人出宰官。", "入內講經千佛現，跏趺對御六龍寒。", "指頭有月娑羅冷，舌上懸河海水乾。", "聖主賜衣漫大地，西方國土未爲寬。"]'),
('d428aa0b-64ae-41cc-844c-122578949c07','再登南樓','鄭起','宋','宋诗','song-poetry','','[]','客中重上倚層臺，天闊雲收八面開。',64,'全唐诗/poet.song.211000.json','["客中重上倚層臺，天闊雲收八面開。", "雁带岳陽秋曉過，浪涵巴峽影西來。", "諸營種柳今何在，老子登樓得幾回。", "自是江山雄壯處，興亡不必問寒灰。"]'),
('d0668140-7b01-4395-921c-ebf1e4fe21a9','思耕','鄭起','宋','宋诗','song-poetry','','[]','江湖漸老身，山澤本來心。',48,'全唐诗/poet.song.211000.json','["江湖漸老身，山澤本來心。", "經濟不敢問，耕耘猶可尋。", "一頃半頃許，三更二更深。", "親朋相接近，雞酒開塵襟。"]'),
('2c58f872-ca03-4459-a752-5332b976fea3','登荆南城樓','鄭起','宋','宋诗','song-poetry','','[]','因爲古荆州，翻成一段愁。',48,'全唐诗/poet.song.211000.json','["因爲古荆州，翻成一段愁。", "孟嘉曾落帽，王粲此登樓。", "唐鄧通襄路，沱潜並漢流。", "太平官府盛，昔日欠來遊。"]'),
('7a0dea7c-81f4-4f79-b2c2-3651a1bce303','宿虎丘','鄭起','宋','宋诗','song-poetry','','[]','到晚歸不去，因而此宿休。',48,'全唐诗/poet.song.211000.json','["到晚歸不去，因而此宿休。", "雲深千古寺，月冷一天秋。", "崖裂池如束，天虛塔欲浮。", "最宜初日上，高處看烟收。"]'),
('d7980c90-dc33-4560-bb9c-3c86599242e2','宿洞霄山中','鄭起','宋','宋诗','song-poetry','','[]','入山時八月，嵐氣似深冬。',48,'全唐诗/poet.song.211000.json','["入山時八月，嵐氣似深冬。", "巖洞生風雨，窠巢落檜松。", "山中九重鎖，月下一聲鐘。", "警省非人世，今秋得異逢。"]'),
('a1eb0abf-feed-426e-b3a7-1e24f9c421b5','喜靜','鄭起','宋','宋诗','song-poetry','','[]','素來嫌僻靜，今漸與相安。',48,'全唐诗/poet.song.211000.json','["素來嫌僻靜，今漸與相安。", "師友凋零盡，年時出處難。", "春風雙屐暖，夜雨一燈寒。", "洙泗曾顔輩，何曾作好官。"]'),
('1a46076c-295d-451b-81c4-bd1785a17144','餘杭界早發','鄭起','宋','宋诗','song-poetry','','[]','早發促程期，籃輿带月低。',48,'全唐诗/poet.song.211000.json','["早發促程期，籃輿带月低。", "山中如白晝，斗下渡清溪。", "群動霜初落，四鄰雞未啼。", "惟聞兵遞舖，星急過淮西。"]'),
('a8ead500-a7ed-465d-a27e-fb79017a4d96','餘杭道上','鄭起','宋','宋诗','song-poetry','','[]','五年茲路上，頻往又頻還。',48,'全唐诗/poet.song.211000.json','["五年茲路上，頻往又頻還。", "歲月孤松老，風霜苦竹班。", "溪流天目水，雲出洞霄山。", "馬上因閒眺，蜉蝣宇宙間。"]'),
('f2b4f00d-78ed-4759-a870-4a8210589a4e','病後','鄭起','宋','宋诗','song-poetry','','[]','漸嬾說功名，修真喜道經。',48,'全唐诗/poet.song.211000.json','["漸嬾說功名，修真喜道經。", "凄凉秋聽雨，空闊夜觀星。", "有病色先見，無心夢最靈。", "階前風葉響，還又感飄零。"]'),
('41536a06-1645-4fdd-9f14-71b742e5cf25','歸去好','鄭起','宋','宋诗','song-poetry','','[]','歸去豈不好，平田带淺林。',48,'全唐诗/poet.song.211000.json','["歸去豈不好，平田带淺林。", "春猿鳴雪澗，晴日上雲岑。", "世久無鳴犢，時當學展禽。", "吾生今老矣，梁父豈能吟。"]'),
('a1719dde-2eeb-4956-8fe0-9642a9bfd15e','送友人之淮','鄭起','宋','宋诗','song-poetry','','[]','積得讀書身，從教此道貧。',48,'全唐诗/poet.song.211000.json','["積得讀書身，從教此道貧。", "逢秋爲遠客，知己是何人。", "天下方多事，西風至不仁。", "但于登眺處，杯酒莫辭頻。"]'),
('6c972ee4-af98-4899-9ade-7c1e97d52815','吳江三高祠堂','鄭起','宋','宋诗','song-poetry','','[]','吾拜三高堂，三高在何許。',48,'全唐诗/poet.song.211000.json','["吾拜三高堂，三高在何許。", "香爐上蒼苔，破屋落大雨。", "石泐水彈痕，地洞龍潛處。", "清魂汗漫遊，芳名垂萬古。"]'),
('5ff8b00b-ace5-4e25-9146-4a2eda524aa2','吳江太湖龍王殿','鄭起','宋','宋诗','song-poetry','','["\u592a\u6e56"]','吾謁龍王殿，龍王在何許。',48,'全唐诗/poet.song.211000.json','["吾謁龍王殿，龍王在何許。", "太湖三萬頃，水族龍爲主。", "離離明月宮，渺渺寒烟渚。", "天下有旱蝗，吾亦能行雨。"]'),
('d6f98b00-e691-4fc3-baaf-bac36e33362f','荆南別賈制書東歸','鄭起','宋','宋诗','song-poetry','','[]','來時秋雨滿江樓，歸日春風度客舟。',32,'全唐诗/poet.song.211000.json','["來時秋雨滿江樓，歸日春風度客舟。", "回首荆南天一角，月明吹笛下揚州。"]'),
('7b4f8e72-0868-491e-9cc5-4e650a7b2a60','送友人之鄂','鄭起','宋','宋诗','song-poetry','','[]','湖海聲名落搢紳，由江而鄂遡鱗鱗。',32,'全唐诗/poet.song.211000.json','["湖海聲名落搢紳，由江而鄂遡鱗鱗。", "煩君黄鶴樓頭看，天下英雄有幾人。"]'),
('e68eed66-3614-430f-8633-e5d2c9b0cd35','晚春即事','鄭起','宋','宋诗','song-poetry','','[]','輕寒時節牡丹開，葉底青青又見梅。',32,'全唐诗/poet.song.211000.json','["輕寒時節牡丹開，葉底青青又見梅。", "門外數枝楊柳薄，一春鶯燕不曾來。"]'),
('14ef4d5e-2546-4303-a71a-ce9753394427','荆江口望見君山','鄭起','宋','宋诗','song-poetry','','[]','荆江江口望漫漫，一白無邊夕照寒。',32,'全唐诗/poet.song.211000.json','["荆江江口望漫漫，一白無邊夕照寒。", "只是青雲浮水上，教人錯認作山看。"]'),
('83ae4e49-cbf2-483e-ab71-ad241326ce9e','繁昌江邊見兩獺祭魚人立而拜','鄭起','宋','宋诗','song-poetry','','[]','寒食清明在客途，片帆飄泊老無廬。',32,'全唐诗/poet.song.211000.json','["寒食清明在客途，片帆飄泊老無廬。", "松楸方念無人掃，忽見江邊獺祭魚。"]'),
('2dc3bf1d-7af3-47f4-888e-859a643f57b8','虎丘尹和靖書院示開講','鄭起','宋','宋诗','song-poetry','','[]','和靖書堂八面開，新分半席在山隈。',32,'全唐诗/poet.song.211000.json','["和靖書堂八面開，新分半席在山隈。", "若無人聽都歸去，傳語生公借石來。"]'),
('edf37de5-a9f1-4e02-b409-a343ed95b598','爲九華王此山賦寧石','鄭起','宋','宋诗','song-poetry','','[]','我謂此山天作石，石不是石人不識。',32,'全唐诗/poet.song.211000.json','["我謂此山天作石，石不是石人不識。", "千年野鶴獨見君，石上採芝石上喫。"]'),
('cf128a5c-660c-49a5-9166-22963e70cc23','關山月','鄭起','宋','宋诗','song-poetry','','[]','霜下月色白，沙飛月色黄。',48,'全唐诗/poet.song.211000.json','["霜下月色白，沙飛月色黄。", "征人此暴露，未有不辛傷。", "滿野髑髏骨，依山魚雁行。", "祁連與瀚海，慘淡更蒼茫。"]'),
('3b6fd140-7d39-48df-af49-f031bd181c64','赤壁歌','鄭起','宋','宋诗','song-poetry','','[]','赤壁山，赤壁水。',42,'全唐诗/poet.song.211000.json','["赤壁山，赤壁水。", "江有蛟龍，野有蛇虺。", "天蒼蒼，雲茫茫。", "周瑜于此走曹操，聲名萬古隨風長。"]'),
('5a46e493-eeb7-4604-bd4f-3bc21d02ad8a','君乘黄','鄭起','宋','宋诗','song-poetry','','[]','君乘黄，臣乘青，二乘先後如流星。',64,'全唐诗/poet.song.211000.json','["君乘黄，臣乘青，二乘先後如流星。", "君乘黄金漆照鏡，臣乘青竹織作櫺。", "道逢相揖失恭敬，君乃傴僂莊其形。", "世人多認車與笠，交道如此今猶馨。"]'),
('3e5f984d-c5f7-435d-b2ef-2c3d4837c43a','天高高','鄭起','宋','宋诗','song-poetry','','[]','天高高兮色青青，夜沉沉兮星熒熒。',28,'全唐诗/poet.song.211000.json','["天高高兮色青青，夜沉沉兮星熒熒。", "不知余命何，所繫兮何星。"]'),
('abaad496-44b1-4db2-bbc9-f07283d5b950','採桑曲','鄭起','宋','宋诗','song-poetry','','[]','晴採桑，雨採桑，田頭陌上家家忙。',32,'全唐诗/poet.song.211000.json','["晴採桑，雨採桑，田頭陌上家家忙。", "去年養蠶十分熟，蠶姑只著麻衣裳。"]'),
('667c9a9b-8706-4323-bd5a-ae5c8482e3ff','樵歌三首  其一','鄭起','宋','宋诗','song-poetry','','[]','上山斸山山丁登，下山嵌山山稜層。',40,'全唐诗/poet.song.211000.json','["上山斸山山丁登，下山嵌山山稜層。", "秋殘日暮歸來晚，茅檐洗脚月又明，明朝早入芙蓉城。"]'),
('3478027e-a208-4035-b95d-322d845cb529','樵歌三首  其二','鄭起','宋','宋诗','song-poetry','','[]','入城不識公與卿，行歌道上旁無人。',40,'全唐诗/poet.song.211000.json','["入城不識公與卿，行歌道上旁無人。", "衣衫藍縷鶉百結，與妻索笑妻生嗔，那知不是朱買臣。"]'),
('1f3ef08a-7f29-41fc-b2ae-71a57f0a3181','樵歌三首  其三','鄭起','宋','宋诗','song-poetry','','[]','山坳築著牧牛兒，白石鑿鑿蒙茸披。',40,'全唐诗/poet.song.211000.json','["山坳築著牧牛兒，白石鑿鑿蒙茸披。", "繆公無人甯戚死，獨吹觱栗誰得知，不如採樵同路歸。"]'),
('38a94c19-2f82-4e5a-bd60-717c673d616f','讀馮道傳','鄭起','宋','宋诗','song-poetry','','[]','西山有薇，二子採之。',80,'全唐诗/poet.song.211000.json','["西山有薇，二子採之。", "二子竟死，薇不療饑。", "匪惡周粟，食不下咽。", "君臣義重，彼蒼者天。", "爾道何人，數主一身。", "有何顔面，冠冕搢紳。", "喬固諸賢，寧死道邊。", "曹操不帝，清議凜然。"]'),
('49e6707b-e2d7-438f-86a8-1dc9b3a95e88','短歌行','鄭起','宋','宋诗','song-poetry','','[]','覽鏡摩挱，歲月蹉跎。',120,'全唐诗/poet.song.211000.json','["覽鏡摩挱，歲月蹉跎。", "道長命窄，憂慮如何。", "何以消除，非酒莫祛。", "醉來不見，醒復如初。", "跖蹻鏘鏘，孔孟皇皇。", "何非何是，孰劣孰强。", "日出杲兮，月出皓兮。", "無風無雨，可以同携。", "人生朝露，保不及暮。", "青青纍纍，皆是墳墓。", "天機轉深，轉用勞心。", "不如坦蕩，驅遣光陰。"]'),
('2a710f2c-4d82-4350-95b6-18429716dabb','飲馬長城窟','鄭起','宋','宋诗','song-poetry','','[]','飲馬長城窟，下見征人骨。',116,'全唐诗/poet.song.211000.json','["飲馬長城窟，下見征人骨。", "長城窟雖深，見骨不見心。", "誰知征人心，怨殺秦至今。", "北邊風打山，草地荒漫漫。", "五月方見青，七月霜便寒。", "古來無井飲，賫带糧盡乾。", "自從征人掘此窟，戍馬飲之如飛翰。", "朝呷一口水，暮破千重關。", "秦皇極是無道理，長城萬里誰能比。"]'),
('f74b1a9b-3d22-4a93-8eca-90309b91d3cd','鄂州南樓','鄭起','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','淳祐六年冬十月，我來獨自上南樓。',192,'全唐诗/poet.song.211000.json','["淳祐六年冬十月，我來獨自上南樓。", "曉霧江山都不見，霧收日出城東頭。", "照見漢陽樹，照見鸚鵡洲。", "浪濤江漢出岷峽，洞庭雲夢天共流。", "大船如龍捲寒碧，小船如葉飛洪溝。", "費褘霞珮跨黄鶴，洞賓玉笛橫清秋。", "泬寥突兀不可狀，開闔風雨晴烟浮。", "空中一一都照見，照見今來古往絲粟無限愁。", "夜郎逐客心膽大，醉欲搥碎醒又休。", "此山此水長不老，英雄消盡山水留。", "何當大雪夜明月，摩挱老眼看九州。", "春風吹雪變紅綠，牛羊被野邊無憂。"]'),
('31f3b65c-d814-4f0e-875e-0c60e52a847f','洞庭君山辭','鄭起','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','山爲君兮水爲臣，水爲臣兮象爲兵。',226,'全唐诗/poet.song.211000.json','["山爲君兮水爲臣，水爲臣兮象爲兵。", "君有定位兮兵無定形，知山知水兮知君臣之性情。", "不知師不知比兮又奚知用兵之精。", "余經山之外兮覩山水之杳冥，佳氣葱鬰兮或天香而龍腥。", "烟雲變化兮或狗狀而人形，風濤洶湧兮或崖立而天平。", "或夕陽兮漁歌，或曉霜兮鐘聲。", "或雪下兮雁叫，或夜半兮鼉鳴。", "或仙人張樂兮霞珮之軿軿，或神丁從駕兮車騎之轔轔。", "冬寒春暖兮湖草幾番之青青，今來古往兮人物幾代之廢興。", "嗟余行役兮顧鬢影之星星，無由登山臨水兮與鷗鷺盟。", "北風吹袂兮又將之荆，徘徊不忍去兮聊以歌而行。"]'),
('afd735fa-22a9-45ad-9616-b53fa1e99643','辭弔富沙梨山大王祠','鄭起','宋','宋诗','song-poetry','','[]','梨山之陽兮有廟煌煌，州人祭享兮釃酒椎羊。',140,'全唐诗/poet.song.211000.json','["梨山之陽兮有廟煌煌，州人祭享兮釃酒椎羊。", "王之未死兮守土此方，王之既死兮州人不忘。", "建山之峭兮建水之長，建秔之粲兮建茗之香。", "州人禱福兮王錫吉祥，魂之來歆兮靈旗央央。", "蛇虎遁伏兮松桂芬芳，梨花燁燁兮王之甘棠。", "自古詩人兮憔悴異常，王之爵位兮何嗇于唐。", "昔駕五馬兮今衣衮裳，詩人之窮兮詩人之昌。"]'),
('205856aa-2b3e-4aee-b298-9acdaa6f5fa2','招魂酹翁賓暘','鄭起','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君之在世帝敕下，君之謝世帝敕回。',265,'全唐诗/poet.song.211000.json','["君之在世帝敕下，君之謝世帝敕回。", "魂之爲變性原返，氣之爲物情本開。", "於戲龍兮鳳兮神氣盛，噫嘻鬼兮歸兮大塊埃。", "身可朽名不可朽，骨可灰神不可灰。", "采石捉月李白非醉，耒陽避水子美非災。", "長孫王吉命不夭，玉川老子詩不俳。", "新城羅隠大奇特，錢塘潘閬終崔嵬。", "陰兮魄兮曷往，陽兮魄兮曷來。", "君其歸來，故交寥落更散漫。", "君其歸來，帝城絢爛可徘徊。", "君其歸來，東西南北不可去。", "君其歸來，春秋霜露令人哀。", "花之明吾無與笑，葉之隕吾實若摧。", "曉猿嘯吾聞淚墮，宵鶴立吾見心猜。", "玉泉其清可鑒，西湖其甘可杯。", "孤山暖梅香可嗅，花翁葬薦菊之隈。", "君其歸來，可伴逋仙之梅，去此又奚之哉。"]'),
('7afcff4d-ffea-4a79-af6b-c5cd3686c692','採蓮曲','鄭起','宋','宋诗','song-poetry','','[]','郎采蓮，妾采蓮，蓮花開似妾初年。',40,'全唐诗/poet.song.211000.json','["郎采蓮，妾采蓮，蓮花開似妾初年。", "蓮房結實妾生子，郎今采取應相憐，暖香雖斷相牽連。"]'),
('c3db27ed-b9cd-4de9-be45-2051ed05b85f','寄題梵才大士台州安隠堂','鄭起','宋','宋诗','song-poetry','','[]','巢禽託靜林，潛魚戀深壑。',96,'全唐诗/poet.song.211000.json','["巢禽託靜林，潛魚戀深壑。", "豈不能自安，翔泳得所樂。", "達士遠紛華，於茲守沖漠。", "堂前鳴松風，堂後馥花藥。", "好鳥時一呼，澄明望寥廓。", "詩興猶不忘，禪心詎云著。", "所以得自然，寧必萬緣縛。", "未能與之游，懷慕徒有作。"]'),
('9c4b9220-ae78-43b8-87ba-f223d9ce74ff','寄題杭州廣法善堂','鄭起','宋','宋诗','song-poetry','','[]','淘清研朱畫屋梁，黄漆柏障連曲房。',64,'全唐诗/poet.song.211000.json','["淘清研朱畫屋梁，黄漆柏障連曲房。", "日暉月色不須照，了了自可窺毫芒。", "夕陰花斂似欲病，飛鳥不驚烏帽郎。", "深山窮谷謾幽僻，喜得吳儂是藥囊。"]'),
('93ca4a4b-cafb-4051-9da6-1c58e04e81f5','題畫蘭','鄭起','宋','宋诗','song-poetry','','[]','向來俯首問羲皇，汝是何人到此鄉。',32,'全唐诗/poet.song.211000.json','["向來俯首問羲皇，汝是何人到此鄉。", "未有畫前開鼻孔，滿天浮動古馨香。"]'),
('79864040-b5b1-484f-aff1-7a0bc291ca3b','句','鄭起','宋','宋诗','song-poetry','','[]','湘妃雨後來池看，碧玉盤中弄水晶。',16,'全唐诗/poet.song.211000.json','["湘妃雨後來池看，碧玉盤中弄水晶。"]'),
('0c4d38f1-81f4-41d5-b15c-4240113f3c20','山居十六詠 入山林處','方岳','宋','宋诗','song-poetry','','[]','窮塗一何慟，多岐一何泣。',24,'全唐诗/poet.song.211000.json','["窮塗一何慟，多岐一何泣。", "指似世間人，路頭從此入。"]'),
('a9e6af1c-e98d-4c97-9b58-854247b5d96e','山居十六詠 幽谷','方岳','宋','宋诗','song-poetry','','[]','入林不厭深，避世不厭獨。',24,'全唐诗/poet.song.211000.json','["入林不厭深，避世不厭獨。", "倦飛鳥知還，毋憚下喬木。"]'),
('8e8a62dc-5753-4a90-9ea7-1b4c225cb967','山居十六詠 便是山','方岳','宋','宋诗','song-poetry','','[]','東臯或巾車，西園亦飛蓋。',24,'全唐诗/poet.song.211000.json','["東臯或巾車，西園亦飛蓋。", "以我方古人，兩脚大自在。"]'),
('a873c88b-0357-4cc4-b4fa-9851f29a2ac2','山居十六詠 石梯','方岳','宋','宋诗','song-poetry','','[]','山險者夷之，梯以石齒齒。',24,'全唐诗/poet.song.211000.json','["山險者夷之，梯以石齒齒。", "於間遂成臺，有梅適堪倚。"]'),
('2e1fe3bf-f4fb-4ace-b602-d94219181acf','山居十六詠 清樾','方岳','宋','宋诗','song-poetry','','[]','山林有灌木，其大可蔽牛。',24,'全唐诗/poet.song.211000.json','["山林有灌木，其大可蔽牛。", "蘚石眠清陰，坐間天地秋。"]'),
('5162bf7e-f6e2-4e09-a34c-2f3ac4b59323','山居十六詠 雪林','方岳','宋','宋诗','song-poetry','','[]','若以雪見我，以林爲吾家。',24,'全唐诗/poet.song.211000.json','["若以雪見我，以林爲吾家。", "君其非詩人，不能識梅花。"]'),
('1e61abc3-1c6f-4760-90fa-2207ba2e3894','山居十六詠 小山','方岳','宋','宋诗','song-poetry','','[]','拳石以爲山，勺水以爲池。',24,'全唐诗/poet.song.211000.json','["拳石以爲山，勺水以爲池。", "我觀於世間，何者非兒嬉。"]'),
('748eccd7-26af-4e6f-9034-c06b9d7f9b7c','山居十六詠 桃李蹊','方岳','宋','宋诗','song-poetry','','[]','竹逕轉西麓，山花能白紅。',24,'全唐诗/poet.song.211000.json','["竹逕轉西麓，山花能白紅。", "要知造物心，政在無言中。"]'),
('1a621d53-ef00-41a3-989a-3fd1f03b68c8','山居十六詠 歸來館','方岳','宋','宋诗','song-poetry','','[]','歸來遽云出，既出又歸來。',24,'全唐诗/poet.song.211000.json','["歸來遽云出，既出又歸來。", "自處苟如此，淵明安在哉。"]'),
('bea51272-28ea-4d7e-85bc-7f5f00af625a','山居十六詠 著圖書所','方岳','宋','宋诗','song-poetry','','[]','鍾乳三千兩，胡椒八百斛。',24,'全唐诗/poet.song.211000.json','["鍾乳三千兩，胡椒八百斛。", "笑殺山中人，破紙塞故屋。"]'),
('6d58280b-ff17-4a26-ba33-d12c4625c593','山居十六詠 草堂','方岳','宋','宋诗','song-poetry','','[]','烟低一片春，留與貧受用。',24,'全唐诗/poet.song.211000.json','["烟低一片春，留與貧受用。", "阿連自能詩，吾衰不復夢。"]'),
('c2bbbad3-dcd5-487d-acab-7a2fe976a0a8','山居十六詠 錦巢','方岳','宋','宋诗','song-poetry','','[]','佳日春酣酣，一色錦步障。',24,'全唐诗/poet.song.211000.json','["佳日春酣酣，一色錦步障。", "誰知山中人，如此富貴相。"]'),
('e72457f4-339f-4bc4-8fe6-864a87106afc','山居十六詠 寒泓','方岳','宋','宋诗','song-poetry','','[]','子盍觀於泉，遇險維其止。',24,'全唐诗/poet.song.211000.json','["子盍觀於泉，遇險維其止。", "流行非所知，一寒清到底。"]'),
('6711ac43-2b06-4900-8ad8-bb81e07007f2','山居十六詠 飯牛庵','方岳','宋','宋诗','song-poetry','','[]','寧與厓下人，烟雨耕犖确。',24,'全唐诗/poet.song.211000.json','["寧與厓下人，烟雨耕犖确。", "讀書亦何爲，謹勿累吾角。"]'),
('409b73e7-2243-4292-b31a-fda3b8a2064b','山居十六詠 秋厓','方岳','宋','宋诗','song-poetry','','[]','鑿空爲此名，忽已落衆口。',24,'全唐诗/poet.song.211000.json','["鑿空爲此名，忽已落衆口。", "聊結一間茅，承當作厓叟。"]'),
('88e4d1a9-e289-41c7-b8bf-1e93e49cfd8e','山居十六詠 田園居','方岳','宋','宋诗','song-poetry','','[]','秋風新飯香，蔬亦美可茹。',24,'全唐诗/poet.song.211000.json','["秋風新飯香，蔬亦美可茹。", "寧知世有人，萬錢無下筯。"]'),
('2d4431bd-d982-4c16-9883-0cc31edfea4e','次韻方蒙仲高人亭  其一','方岳','宋','宋诗','song-poetry','','[]','此君款吾室，高人跂吾亭。',24,'全唐诗/poet.song.211000.json','["此君款吾室，高人跂吾亭。", "邂逅兩相逆，保此歲晚青。"]'),
('a6511466-6060-40df-9920-4e3310aed1e2','次韻方蒙仲高人亭  其二','方岳','宋','宋诗','song-poetry','','[]','茗盌漱藜莧，詩腸許堅頑。',24,'全唐诗/poet.song.211000.json','["茗盌漱藜莧，詩腸許堅頑。", "是間可無我，不可無此山。"]'),
('23fca28d-75a8-4670-93c3-0d79a41b1199','次韻方蒙仲高人亭  其三','方岳','宋','宋诗','song-poetry','','[]','鷗鷺之與侶，竹石之與居。',24,'全唐诗/poet.song.211000.json','["鷗鷺之與侶，竹石之與居。", "子虛亡是公，付之渴相如。"]'),
('4efaa224-5db0-4518-aae3-eb0e0de9c2b2','次韻方蒙仲高人亭  其四','方岳','宋','宋诗','song-poetry','','[]','苔寒兩不借，對面寧爾勞。',24,'全唐诗/poet.song.211000.json','["苔寒兩不借，對面寧爾勞。", "欲語二三子，卑之毋甚高。"]'),
('ddbcae56-82b8-4812-987d-f43308d53004','次韻方蒙仲高人亭  其五','方岳','宋','宋诗','song-poetry','','[]','愛之不我疎，狎則不我親。',24,'全唐诗/poet.song.211000.json','["愛之不我疎，狎則不我親。", "山耶其竹歟，君子哉若人。"]'),
('4bd8ca03-06bd-41f0-9b54-865b2f39a2e4','次韻方蒙仲高人亭  其六','方岳','宋','宋诗','song-poetry','','[]','吾儕磊塊胸，所見不相遠。',24,'全唐诗/poet.song.211000.json','["吾儕磊塊胸，所見不相遠。", "借我竹外山，一榻供晝偃。"]'),
('c8809748-135f-45d7-88f6-b11e2e819086','次韻方蒙仲高人亭  其七','方岳','宋','宋诗','song-poetry','','[]','烟霏日夕佳，隠固勝於顯。',24,'全唐诗/poet.song.211000.json','["烟霏日夕佳，隠固勝於顯。", "孰從而詩之，要亦山一蹇。"]'),
('11323d50-c9b9-4916-a030-52678bdb7452','次韻方蒙仲高人亭  其八','方岳','宋','宋诗','song-poetry','','[]','終南有捷徑，澗恧而林羞。',24,'全唐诗/poet.song.211000.json','["終南有捷徑，澗恧而林羞。", "其人豈其山，寧勿相累不。"]'),
('9b46589c-2566-4330-bf69-47e4dd4bd2e4','次韻方蒙仲高人亭  其九','方岳','宋','宋诗','song-poetry','','[]','相從文字盟，不與如此酒。',24,'全唐诗/poet.song.211000.json','["相從文字盟，不與如此酒。", "他日有移文，毋令猿鶴受。"]'),
('3469f001-66ac-4f03-989d-430f35dbfa60','次韻方蒙仲高人亭  其一○','方岳','宋','宋诗','song-poetry','','[]','老子可林壑，諸公自烟霄。',24,'全唐诗/poet.song.211000.json','["老子可林壑，諸公自烟霄。", "緬懷歸耕歸，底用招隠招。"]'),
('91e63ed0-0188-4cc5-bd63-ab7afb8bd0c7','以嗜酒愛風竹卜居此林泉爲韻作十小詩  其一','方岳','宋','宋诗','song-poetry','','[]','居千卿者三，至九卿者四。',24,'全唐诗/poet.song.211000.json','["居千卿者三，至九卿者四。", "不博牛背眠，鹹酸信殊嗜。"]'),
('6b3d3e0d-783e-4a2f-947f-68b85e00497a','以嗜酒愛風竹卜居此林泉爲韻作十小詩  其二','方岳','宋','宋诗','song-poetry','','[]','玉虹橫吾腰，金貂直吾首。',24,'全唐诗/poet.song.211000.json','["玉虹橫吾腰，金貂直吾首。", "寧知千載名，不如一杯酒。"]'),
('bfac29cd-60c1-41d2-9b40-938b2465865b','以嗜酒愛風竹卜居此林泉爲韻作十小詩  其三','方岳','宋','宋诗','song-poetry','','[]','事有俄頃間，遺臭及萬代。',24,'全唐诗/poet.song.211000.json','["事有俄頃間，遺臭及萬代。", "吾觀於斯人，不過一字愛。"]'),
