('75e83bb9-d801-4fa7-b10c-24b48c9b4966','陪劉提察少集四聖觀  其一','方岳','宋','宋诗','song-poetry','','[]','江山於我故眼青，我亦輒以詩酬之。',32,'全唐诗/poet.song.211000.json','["江山於我故眼青，我亦輒以詩酬之。", "東華昨夢已塵土，千萬勿令鷗鷺知。"]'),
('42cb0c2f-f0a7-4001-9a79-dbb372fd2515','陪劉提察少集四聖觀  其二','方岳','宋','宋诗','song-poetry','','[]','詩人胸次倒磊塊，試澆之酒將何如。',32,'全唐诗/poet.song.211000.json','["詩人胸次倒磊塊，試澆之酒將何如。", "作詩不壓林逋倒，正恐湖山亦厭余。"]'),
('b6468a13-cae3-4584-b31e-3579d1641753','宿芳潤用壁間韻','方岳','宋','宋诗','song-poetry','','[]','只爲梧桐怨夜長，不知楊柳老年芳。',32,'全唐诗/poet.song.211000.json','["只爲梧桐怨夜長，不知楊柳老年芳。", "林梢一片過雲雨，便作秋聲占取凉。"]'),
('202e7a61-1439-4746-a3f7-b299d47fc142','次韻牟監簿  其一','方岳','宋','宋诗','song-poetry','','[]','幾携筆硯傍書林，吟到更寒月未沈。',32,'全唐诗/poet.song.211000.json','["幾携筆硯傍書林，吟到更寒月未沈。", "有客忽從天祿至，人間便隔五雲深。"]'),
('ec66676d-1b05-4918-a6c3-5ade74d31f51','次韻牟監簿  其二','方岳','宋','宋诗','song-poetry','','[]','秋聲滿院有誰來，亦欲從君話老懷。',32,'全唐诗/poet.song.211000.json','["秋聲滿院有誰來，亦欲從君話老懷。", "隔竹已敲茶臼雪，不知何日又清齋。"]'),
('36d2e15e-86fa-4f99-b284-ec4a23d4db98','夢放翁爲予作貧樂齋扁誠齋許畫齋壁予本無是齋亦不省誠齋之能畫也','方岳','宋','宋诗','song-poetry','','[]','晴窗欲曉鳥聲春，喚起藜床入定身。',32,'全唐诗/poet.song.211000.json','["晴窗欲曉鳥聲春，喚起藜床入定身。", "老去不知三月暮，夢中親見兩詩人。"]'),
('74fb0801-2372-4c41-90cf-2b040a25061c','早春山中  其一','方岳','宋','宋诗','song-poetry','','[]','空濛山翠濕烏紗，逗密穿深一逕斜。',32,'全唐诗/poet.song.211000.json','["空濛山翠濕烏紗，逗密穿深一逕斜。", "誰畫秋厓滿頭雪，石壇倚竹看梅花。"]'),
('b31fb177-ed56-42bc-bfdd-bc91743b676e','早春山中  其二','方岳','宋','宋诗','song-poetry','','[]','竹邊門自不須關，留與山雲共往還。',32,'全唐诗/poet.song.211000.json','["竹邊門自不須關，留與山雲共往還。", "芳草初齊梅點點，綠絲茸地鹿胎斑。"]'),
('9ccc9847-fd77-416d-85c4-ca01b1fee52b','早春山中  其三','方岳','宋','宋诗','song-poetry','','[]','蘭未曾芽柳未絲，是渠春早是春遲。',32,'全唐诗/poet.song.211000.json','["蘭未曾芽柳未絲，是渠春早是春遲。", "草塘尋見春風處，問訊如何自不知。"]'),
('993688cd-5886-4470-a4d9-0980b3cf21ef','早春山中  其四','方岳','宋','宋诗','song-poetry','','[]','吟入梅花倚樹腰，不知聲撼雪飄飄。',32,'全唐诗/poet.song.211000.json','["吟入梅花倚樹腰，不知聲撼雪飄飄。", "山翁只道春無力，半日黏鬚未肯消。"]'),
('8458a044-ca32-4c22-bcd9-d5517b4394f2','早春山中  其五','方岳','宋','宋诗','song-poetry','','[]','同時乞得杏花栽，一樣高低一處裁。',32,'全唐诗/poet.song.211000.json','["同時乞得杏花栽，一樣高低一處裁。", "自是春風不齊整，半零落盡半胚胎。"]'),
('c39a1628-0878-4273-92ec-d9589cb829e6','元夕  其一','方岳','宋','宋诗','song-poetry','','[]','團蒲曲几雪鬅鬙，寒入青燈澹似僧。',32,'全唐诗/poet.song.211000.json','["團蒲曲几雪鬅鬙，寒入青燈澹似僧。", "只有梅花一林月，酒盃詩筆已無能。"]'),
('b0f3a36b-3fd5-494a-9368-002a8be755de','元夕  其二','方岳','宋','宋诗','song-poetry','','[]','去年人老已蒼華，野蔌山醪辦咄嗟。',32,'全唐诗/poet.song.211000.json','["去年人老已蒼華，野蔌山醪辦咄嗟。", "到得今年人又老，也無筋力看梅花。"]'),
('6a695429-cdcf-4450-8567-da1668bcd462','元夕  其三','方岳','宋','宋诗','song-poetry','','[]','莫道山家不挂燈，脩身寶月一團冰。',32,'全唐诗/poet.song.211000.json','["莫道山家不挂燈，脩身寶月一團冰。", "清寒照見諸人膽，却問諸人見未曾。"]'),
('a163f844-8411-411d-b172-bdbbeddec325','元夕  其四','方岳','宋','宋诗','song-poetry','','[]','老去歡悰久已無，病來瘦骨不勝扶。',32,'全唐诗/poet.song.211000.json','["老去歡悰久已無，病來瘦骨不勝扶。", "山居幸自依青士，身事何曾問紫姑。"]'),
('59bd640c-281d-4c50-bed9-4e05d9fb7045','入村  其一','方岳','宋','宋诗','song-poetry','','[]','十日春霖一日晴，打包作意辦山行。',32,'全唐诗/poet.song.211000.json','["十日春霖一日晴，打包作意辦山行。", "月明夜半雨聲急，不道老天無十成。"]'),
('3204d3fd-3784-4614-9b8b-7654aae0580a','入村  其二','方岳','宋','宋诗','song-poetry','','[]','山深未必得春遲，處處山櫻花壓枝。',32,'全唐诗/poet.song.211000.json','["山深未必得春遲，處處山櫻花壓枝。", "桃李不言隨雨意，亦知終是有晴時。"]'),
('60595d96-3bbf-41d1-96be-f8a60fcf616e','入村  其三','方岳','宋','宋诗','song-poetry','','[]','閉門覓句每無悰，句在茅茨烟雨中。',32,'全唐诗/poet.song.211000.json','["閉門覓句每無悰，句在茅茨烟雨中。", "和烟和雨收拾取，等晴却寫與東風。"]'),
('6512291f-a02f-4b89-875c-7d4a4431e9e6','入村  其四','方岳','宋','宋诗','song-poetry','','[]','宿雨初晴曉日晶，彌川滿谷白雲平。',32,'全唐诗/poet.song.211000.json','["宿雨初晴曉日晶，彌川滿谷白雲平。", "爛銀堆裏素螺髻，畫出江潮萬里橫。"]'),
('d1d106bc-754c-4b10-832e-742d2a8e5ad0','雁來紅  其一','方岳','宋','宋诗','song-poetry','','[]','是葉青青花片紅，剪裁無巧似春風。',32,'全唐诗/poet.song.211000.json','["是葉青青花片紅，剪裁無巧似春風。", "誰將葉作花顔色，更與春風迥不同。"]'),
('fbd6b016-75fb-46e1-8092-4015c460b52b','雁來紅  其二','方岳','宋','宋诗','song-poetry','','[]','秋入山籬葉正丹，老天渾誤作花看。',32,'全唐诗/poet.song.211000.json','["秋入山籬葉正丹，老天渾誤作花看。", "不知宋玉今何似，雁欲來時霜正寒。"]'),
('340071be-33e0-4739-9607-a52e39c9ac22','月下  其一','方岳','宋','宋诗','song-poetry','','[]','月明正午一聲雁，山靜如秋兩袖風。',32,'全唐诗/poet.song.211000.json','["月明正午一聲雁，山靜如秋兩袖風。", "鶴與蒼頭齊睡著，無人知我此山中。"]'),
('9024d5f0-ae31-4ca2-9121-dbe7895aad8e','月下  其二','方岳','宋','宋诗','song-poetry','','[]','春風不到莓苔石，山月自隨烟水身。',32,'全唐诗/poet.song.211000.json','["春風不到莓苔石，山月自隨烟水身。", "窮是世間常事耳，不知顛倒幾多人。"]'),
('02635dd5-8a9d-49d8-a347-84c225cf05d5','買蘭','方岳','宋','宋诗','song-poetry','','[]','幾人曾識離騷面，說與蘭花枉自開。',32,'全唐诗/poet.song.211000.json','["幾人曾識離騷面，說與蘭花枉自開。", "却是樵夫生鼻孔，擔頭带得入城來。"]'),
('450b7f76-11b5-49f4-8bcb-b3540ce286be','荼䕷  其一','方岳','宋','宋诗','song-poetry','','[]','山徑陰陰雨未乾，春風已暖却成寒。',32,'全唐诗/poet.song.211000.json','["山徑陰陰雨未乾，春風已暖却成寒。", "不緣天氣渾無準，要護荼䕷繼牡丹。"]'),
('4cf4fb66-2ae5-4243-bb38-72fbc9a5d7d2','荼䕷  其二','方岳','宋','宋诗','song-poetry','','[]','手插春風十萬條，野香落絮玉摇摇。',32,'全唐诗/poet.song.211000.json','["手插春風十萬條，野香落絮玉摇摇。", "黄鸝莫誤看花眼，等得南薰雪未消。"]'),
('3afa1372-c975-4f3f-ac75-7230d5781ef9','牡丹多不開花','方岳','宋','宋诗','song-poetry','','[]','少作花頭多作叢，十分能有幾分紅。',32,'全唐诗/poet.song.211000.json','["少作花頭多作叢，十分能有幾分紅。", "春工自不容人力，抱甕窮年笑此翁。"]'),
('62c38b6e-58ff-48d2-b0fb-31dad26d8e6f','觀荷  其一','方岳','宋','宋诗','song-poetry','','[]','南薰獨擅水雲鄉，不許人間別有香。',32,'全唐诗/poet.song.211000.json','["南薰獨擅水雲鄉，不許人間別有香。", "是草是花開一遍，春風却似欠商量。"]'),
('88947307-7815-410c-b972-af997b0877b0','觀荷  其二','方岳','宋','宋诗','song-poetry','','[]','春紅樹樹或叢叢，一一托根塵土中。',32,'全唐诗/poet.song.211000.json','["春紅樹樹或叢叢，一一托根塵土中。", "不道獨清冰氏子，炎天玉立水晶宮。"]'),
('dfcce555-73af-400e-859e-4eacda49df94','觀荷  其三','方岳','宋','宋诗','song-poetry','','[]','紅紅白白兩娉婷，一種風流各典刑。',32,'全唐诗/poet.song.211000.json','["紅紅白白兩娉婷，一種風流各典刑。", "紅亦非紅白非白，阿嬌微醉阿環醒。"]'),
('7163cdcc-8999-46c5-97a6-46161fe4d489','觀荷  其四','方岳','宋','宋诗','song-poetry','','[]','蓮有濂溪梅有逋，兩家言句滿江湖。',32,'全唐诗/poet.song.211000.json','["蓮有濂溪梅有逋，兩家言句滿江湖。", "自憐尚與梅花隔，曾識先生太極圖。"]'),
('28d32c9d-08df-4871-81e3-4775dd7583f3','觀荷  其五','方岳','宋','宋诗','song-poetry','','[]','花葉根莖迥不同，略無些子犯春風。',32,'全唐诗/poet.song.211000.json','["花葉根莖迥不同，略無些子犯春風。", "羽衣縱落尋芳後，解作清凉烈日中。"]'),
('8fab1d54-9063-4992-b631-f22c8177a2e3','山橋月夜','方岳','宋','宋诗','song-poetry','','[]','寒聲策策琅玕碧，香氣浮浮菡萏紅。',32,'全唐诗/poet.song.211000.json','["寒聲策策琅玕碧，香氣浮浮菡萏紅。", "六月人間苦炎熱，獨搔殘雪月明中。"]'),
('cc60c6ac-9486-45ed-93ca-16c112ea05b2','秋熱  其一','方岳','宋','宋诗','song-poetry','','[]','藴隆日日等西風，等得西風更藴隆。',32,'全唐诗/poet.song.211000.json','["藴隆日日等西風，等得西風更藴隆。", "四十日秋無點雨，誰將消息到梧桐。"]'),
('05d175bf-5f4e-4e16-a9b8-a0a85cca09fc','秋熱  其二','方岳','宋','宋诗','song-poetry','','[]','山氣爞爞旱火光，牆頭枯草半青黄。',32,'全唐诗/poet.song.211000.json','["山氣爞爞旱火光，牆頭枯草半青黄。", "饑腸慣作晴雷吼，且乞梧桐一夜凉。"]'),
('81df9588-1d09-47ed-b35e-aafc6dd5d1ab','晚秋猶熱  其一','方岳','宋','宋诗','song-poetry','','[]','九月年時已肅霜，今年九月尚追凉。',32,'全唐诗/poet.song.211000.json','["九月年時已肅霜，今年九月尚追凉。", "幸吾絺綌猶無恙，杜老何煩苦自傷。"]'),
('02d2ac9b-4381-47b7-b7b8-2b5f28985467','晚秋猶熱  其二','方岳','宋','宋诗','song-poetry','','[]','適自相遭各有時，莫悲團扇與秋辭。',32,'全唐诗/poet.song.211000.json','["適自相遭各有時，莫悲團扇與秋辭。", "班姬不死天無準，定悔當時作許悲。"]'),
('62218612-2918-41a6-8f5f-027cc6efbdd5','即事十首  其一','方岳','宋','宋诗','song-poetry','','[]','窺園何物慍無端，疥手偷將玉雪團。',32,'全唐诗/poet.song.211000.json','["窺園何物慍無端，疥手偷將玉雪團。", "不道主林神忌諱，鳥烏聲樂併催殘。"]'),
