('dbd9c4b2-f834-45de-b617-1d9e84767bf7','即事十首  其三','方岳','宋','宋诗','song-poetry','','[]','畦丁亸懶欲誰欺，趁我山行始一犂。',32,'全唐诗/poet.song.211000.json','["畦丁亸懶欲誰欺，趁我山行始一犂。", "只有山花山鳥笑，主人元自不曾知。"]'),
('eeb8cd13-08ee-4bd4-86ec-b8a4ee1739eb','即事十首  其四','方岳','宋','宋诗','song-poetry','','[]','藤蔓穿籬礙草扉，與僮扶起繞松圍。',32,'全唐诗/poet.song.211000.json','["藤蔓穿籬礙草扉，與僮扶起繞松圍。", "髯龍鱗甲動雲雨，縛著空山莫遣飛。"]'),
('75c532d7-4b92-4c34-af7a-8256418a90a4','即事十首  其五','方岳','宋','宋诗','song-poetry','','[]','龍骨翻翻水倒流，藕花借與稻花秋。',32,'全唐诗/poet.song.211000.json','["龍骨翻翻水倒流，藕花借與稻花秋。", "魚兼熊掌不可得，寧負風光救口休。"]'),
('8d46068d-8df4-4d7d-82a7-26d567561b19','即事十首  其六','方岳','宋','宋诗','song-poetry','','[]','記得秋風此削瓜，偶遺子亦自成花。',32,'全唐诗/poet.song.211000.json','["記得秋風此削瓜，偶遺子亦自成花。", "生生造化無終極，但有根芽未可涯。"]'),
('3d33472c-80fe-4a70-a523-aef09d3f7916','即事十首  其七','方岳','宋','宋诗','song-poetry','','[]','巖暝林霏日夕佳，百年寧復此秋崖。',32,'全唐诗/poet.song.211000.json','["巖暝林霏日夕佳，百年寧復此秋崖。", "不須更問青烏子，一鍤相隨死便埋。"]'),
