('b76998d4-7ea5-4330-8fe0-cd2097c42ebb','賣花翁','方岳','宋','宋诗','song-poetry','','[]','不論袍紫與鞓紅，一朵千金費化工。',32,'全唐诗/poet.song.212000.json','["不論袍紫與鞓紅，一朵千金費化工。", "人共醉花花亦醉，莫教山圃不春風。"]'),
('faaf4c1d-64a3-4a84-9b9c-dfb6f2518382','汪聖權自開壽域作小亭其前植桂環之謁予作扁有詩云不分桂籍一毫月枉踏槐花十八秋其志亦可悲也已爲題曰桂穴而系之詩  其一','方岳','宋','宋诗','song-poetry','','[]','老蠶作繭自纏裹，不肯生前只麽休。',32,'全唐诗/poet.song.212000.json','["老蠶作繭自纏裹，不肯生前只麽休。", "却後百年牢記取，滿身明月桂花秋。"]'),
('d4ce3f8a-749f-4960-ae01-d4886c68daec','汪聖權自開壽域作小亭其前植桂環之謁予作扁有詩云不分桂籍一毫月枉踏槐花十八秋其志亦可悲也已爲題曰桂穴而系之詩  其二','方岳','宋','宋诗','song-poetry','','[]','白頭不了秋風債，桂穴鋤雲種一枝。',32,'全唐诗/poet.song.212000.json','["白頭不了秋風債，桂穴鋤雲種一枝。", "與世今迷日五色，莫教地下有人知。"]'),
('0fd449dd-9323-43cb-a7b4-67aa3894730d','獨立  其一','方岳','宋','宋诗','song-poetry','','[]','村夫子挾兔園冊，教得黄鸝解讀書。',32,'全唐诗/poet.song.212000.json','["村夫子挾兔園冊，教得黄鸝解讀書。", "能記蒙求中一句，百般嬌姹可憐渠。"]'),
('37c33b16-2691-40af-b1bb-749c1172e5f9','獨立  其二','方岳','宋','宋诗','song-poetry','','[]','從來人說天難做，纔怨春陰又怨晴。',32,'全唐诗/poet.song.212000.json','["從來人說天難做，纔怨春陰又怨晴。", "昨夜雷驅三尺水，更愁橋斷不通行。"]'),
('da90715d-de1a-4cf4-8e73-30815c88c68f','贈談命者趙生自號千兩金','方岳','宋','宋诗','song-poetry','','[]','人間萬事一盃酒，之子五行千兩金。',32,'全唐诗/poet.song.212000.json','["人間萬事一盃酒，之子五行千兩金。", "聽我自窮詩自老，半江明月葦花深。"]'),
('9b181112-931e-4104-b455-eee9c0419269','至日','方岳','宋','宋诗','song-poetry','','[]','至日觀書不幾行，梅梢橫影月昏黄。',32,'全唐诗/poet.song.212000.json','["至日觀書不幾行，梅梢橫影月昏黄。", "漢家紅影無人見，未必曾添一線長。"]'),
('4fd25af1-9cc2-4215-876f-44957495ef5f','梅花十絕  其一','方岳','宋','宋诗','song-poetry','','[]','儘道春風有等差，從前謾語待詩家。',32,'全唐诗/poet.song.212000.json','["儘道春風有等差，從前謾語待詩家。", "今年雪屋親曾見，的當南枝先著花。"]'),
('9e24532f-4d97-4f52-be32-4b3f41b04250','梅花十絕  其二','方岳','宋','宋诗','song-poetry','','[]','日日尋梅未肯春，幾番和月倚吟身。',32,'全唐诗/poet.song.212000.json','["日日尋梅未肯春，幾番和月倚吟身。", "一枝斜入叢篁裏，人不見渠渠見人。"]'),
('2ac43f23-1a7d-4e4b-8e4b-7848f3af1d27','梅花十絕  其三','方岳','宋','宋诗','song-poetry','','[]','自有詩來幾許詩，玉堂吹徹又茅茨。',32,'全唐诗/poet.song.212000.json','["自有詩來幾許詩，玉堂吹徹又茅茨。", "阿誰不愛梅花句，未省梅花愛阿誰。"]'),
('ab733a45-3c42-49c9-b842-a0c3c425e916','梅花十絕  其四','方岳','宋','宋诗','song-poetry','','[]','是處溪橋淺带流，山中別有一深幽。',32,'全唐诗/poet.song.212000.json','["是處溪橋淺带流，山中別有一深幽。", "規模略比林君復，開上風烟頂𩕳頭。"]'),
('3c763dbd-d4dc-4493-a01a-a223d4a101ff','梅花十絕  其五','方岳','宋','宋诗','song-poetry','','[]','自插斜枝墊角巾，詩狂又有老精神。',32,'全唐诗/poet.song.212000.json','["自插斜枝墊角巾，詩狂又有老精神。", "黄昏酒醒欲歸去，月出山來喚住人。"]'),
('a355f279-594b-44f8-b980-9030f5c15bb7','梅花十絕  其六','方岳','宋','宋诗','song-poetry','','[]','老樹生苔凍欲枯，山村雪意晚糢糊。',32,'全唐诗/poet.song.212000.json','["老樹生苔凍欲枯，山村雪意晚糢糊。", "一梢橫打竹邊過，造化工成水墨圖。"]'),
('f27d54eb-2a03-46bf-a7a1-15008081f2d2','梅花十絕  其七','方岳','宋','宋诗','song-poetry','','[]','逋僊解道影南斜，二百年來蔑以加。',32,'全唐诗/poet.song.212000.json','["逋僊解道影南斜，二百年來蔑以加。", "別有脫胎詩一句，自從梅後更無花。"]'),
('b855ba37-9b22-4813-a19c-c7b8c840d79c','梅花十絕  其八','方岳','宋','宋诗','song-poetry','','[]','三分香有七分清，月冷霜寒太瘦生。',32,'全唐诗/poet.song.212000.json','["三分香有七分清，月冷霜寒太瘦生。", "山澤之儒君識否，樂天姓氏謫僊名。"]'),
('19679dd0-2bce-46d5-a8a2-1563fa819c3c','梅花十絕  其九','方岳','宋','宋诗','song-poetry','','["\u5199\u96ea", "\u51ac\u5929", "\u96ea", "\u6885\u82b1"]','有梅無雪不精神，有雪無詩俗了人。',32,'全唐诗/poet.song.212000.json','["有梅無雪不精神，有雪無詩俗了人。", "薄暮詩成天又雪，與梅併作十分春。"]'),
('8e2d0b2b-50a5-49b4-b988-2f298b7ae051','梅花十絕  其一○','方岳','宋','宋诗','song-poetry','','[]','竹緣貨殖比封君，松愛微官不避秦。',32,'全唐诗/poet.song.212000.json','["竹緣貨殖比封君，松愛微官不避秦。", "至竟羞與噲等伍，歲寒誰障庾公塵。"]'),
('d40a9ecd-040c-4146-adcf-0bac4b48a849','即事  其一','方岳','宋','宋诗','song-poetry','','[]','野逕孤橫雪外枝，歲寒了不受春知。',32,'全唐诗/poet.song.212000.json','["野逕孤橫雪外枝，歲寒了不受春知。", "世間所謂奇男子，除却梅花更是誰。"]'),
('1747ffbb-573d-459f-a5b1-861030d1f8ae','即事  其二','方岳','宋','宋诗','song-poetry','','[]','荒烟疎樹野人家，竹外尋詩一逕斜。',32,'全唐诗/poet.song.212000.json','["荒烟疎樹野人家，竹外尋詩一逕斜。", "山鳥亦知人意思，忽翻殘雪啄梅花。"]'),
('ce8e3068-e205-4c85-b147-f922f2bc0f31','二月朔日食陰雨不見','方岳','宋','宋诗','song-poetry','','[]','飛飛細雨濕花朝，不省陽烏影動摇。',32,'全唐诗/poet.song.212000.json','["飛飛細雨濕花朝，不省陽烏影動摇。", "晚色漏晴山又紫，始知陰沴已潛消。"]'),
('af9f6744-9940-4213-8087-e9bb6a78b33c','苦雨  其一','方岳','宋','宋诗','song-poetry','','[]','稼欲登場只等晴，入倉方始是收成。',32,'全唐诗/poet.song.212000.json','["稼欲登場只等晴，入倉方始是收成。", "雨須小住爲佳耳，已約鄰翁話太平。"]'),
('ebc23666-3521-4574-ae7c-666dce3d8e50','苦雨  其二','方岳','宋','宋诗','song-poetry','','[]','翁自無田望有秋，有秋翁自飽齁齁。',32,'全唐诗/poet.song.212000.json','["翁自無田望有秋，有秋翁自飽齁齁。", "此愁不遣吾人管，欲遣何人管此愁。"]'),
('405b135e-9250-4c98-bb92-54b0e8e19899','除夜  其一','方岳','宋','宋诗','song-poetry','','[]','日月無根走彈丸，年來年去幾椒盤。',32,'全唐诗/poet.song.212000.json','["日月無根走彈丸，年來年去幾椒盤。", "秋崖老却渾閒事，老却梅花不耐寒。"]'),
('ce89f562-17de-437f-871b-480d05dc4d94','除夜  其二','方岳','宋','宋诗','song-poetry','','[]','莫嫌工部太侵尋，老杜稱呼直到今。',32,'全唐诗/poet.song.212000.json','["莫嫌工部太侵尋，老杜稱呼直到今。", "我但六年難改口，不知老杜更年深。"]'),
('71426292-1c68-4e3f-b475-18317cec6ae5','除夜  其三','方岳','宋','宋诗','song-poetry','','[]','春缸落面滑於油，旋潑醅來不用篘。',32,'全唐诗/poet.song.212000.json','["春缸落面滑於油，旋潑醅來不用篘。", "窮鬼相隨政相熟，莫題荼壘惱渠休。"]'),
('f00a176c-5559-4620-a33e-86e9f5d90252','除夜  其四','方岳','宋','宋诗','song-poetry','','[]','山中寒盡不知年，只道梅花欲雪天。',32,'全唐诗/poet.song.212000.json','["山中寒盡不知年，只道梅花欲雪天。", "未到五更春已動，乾坤生意本無邊。"]'),
('8d3ae5f4-fea5-4945-9722-4bbcd40144e8','除夜  其五','方岳','宋','宋诗','song-poetry','','[]','不是催租夜打門，那知寶祐改新元。',32,'全唐诗/poet.song.212000.json','["不是催租夜打門，那知寶祐改新元。", "人間測度春風意，李白桃紅又一番。"]'),
('5fe06743-feec-45c5-8911-a2bc262d0f75','除夜  其六','方岳','宋','宋诗','song-poetry','','[]','盡處生機衮衮新，花情柳思已精神。',32,'全唐诗/poet.song.212000.json','["盡處生機衮衮新，花情柳思已精神。", "歲堂堂去誰能守，睡到明朝又是春。"]'),
('7014d6df-a4c7-4124-870e-571621b59476','立春日雷  其一','方岳','宋','宋诗','song-poetry','','[]','勝裏春從午夜回，自挑生菜壓春醅。',32,'全唐诗/poet.song.212000.json','["勝裏春從午夜回，自挑生菜壓春醅。", "阿香不解人間事，便駕雷車送雨來。"]'),
('44be170d-f2c8-4e4d-88a3-3637c6f58435','立春日雷  其二','方岳','宋','宋诗','song-poetry','','[]','出地奔霆便發聲，寒花衰草亦欣榮。',32,'全唐诗/poet.song.212000.json','["出地奔霆便發聲，寒花衰草亦欣榮。", "天公只要新羣聽，不等春來蟄已驚。"]'),
('82721fd3-dd6a-4e68-b5f0-1fa1f36078ec','獨立','方岳','宋','宋诗','song-poetry','','[]','茅茨烟樹水溶溶，籬落人家带晚舂。',32,'全唐诗/poet.song.212000.json','["茅茨烟樹水溶溶，籬落人家带晚舂。", "獨立西風無一事，自撐短艇看芙蓉。"]'),
('13d38e85-6193-4559-b232-c6a5d0c26ee1','悼栖雲主人','方岳','宋','宋诗','song-poetry','','[]','羽士巖前烟樹深，亂雲堆屋自無心。',32,'全唐诗/poet.song.212000.json','["羽士巖前烟樹深，亂雲堆屋自無心。", "鶴驚蕙帳夜岑寂，霜月正寒愁不禁。"]'),
('ea115151-b1c3-478c-ade2-9edcb4d99db9','挽曹侍郎  其一','方岳','宋','宋诗','song-poetry','','[]','諸老各凋零，公乎獨典刑。',48,'全唐诗/poet.song.212000.json','["諸老各凋零，公乎獨典刑。", "草堂春得句，雪戶夜談經。", "歲月頭從白，江山眼共青。", "斯文今已矣，天亦自冥冥。"]'),
('7a6dc6d4-5ef7-40a8-91de-04cc5279f646','挽曹侍郎  其二','方岳','宋','宋诗','song-poetry','','[]','一角玉麟寒，何心獬豸冠。',48,'全唐诗/poet.song.212000.json','["一角玉麟寒，何心獬豸冠。", "滿腔秋沆瀣，披腹玉琅玕。", "講入經三昧，書成義不刊。", "陽城遺碣在，老淚不勝彈。"]'),
('d29fc254-c126-4c8a-a4b5-f46fa6d33a65','挽曹侍郎  其三','方岳','宋','宋诗','song-poetry','','[]','筆橐上嚴宸，真爲侍從臣。',48,'全唐诗/poet.song.212000.json','["筆橐上嚴宸，真爲侍從臣。", "袖中周禮在，言外孔堂春。", "亟草閒居賦，寧慙勇退人。", "空餘文作塚，書带已成塵。"]'),
('7800bf5d-3844-44ea-a19e-60df908f08ae','挽曹侍郎  其四','方岳','宋','宋诗','song-poetry','','[]','我昔識平川，初鳴偃室絃。',48,'全唐诗/poet.song.212000.json','["我昔識平川，初鳴偃室絃。", "議題春雨夜，探榜晚秋天。", "兩柳今安在，枯梅畫不傳。", "向來詩酒地，獨立意茫然。"]'),
('7b9771da-5d05-414f-9c45-3184c90dd7e8','齋宿學宮','方岳','宋','宋诗','song-poetry','','[]','竹外一燈青，殘書伴古廳。',48,'全唐诗/poet.song.212000.json','["竹外一燈青，殘書伴古廳。", "葉乾聞雨急，山近覺嵐腥。", "多病身爲累，無心夢亦靈。", "明朝有癡事，須到采芹亭。"]'),
('1a523ce5-ece4-4d08-bd20-1e392e932877','山居十首  其一','方岳','宋','宋诗','song-poetry','','[]','我愛山居好，林梢一片晴。',48,'全唐诗/poet.song.212000.json','["我愛山居好，林梢一片晴。", "野烟禽誶語，春水柳閒情。", "蘚石隨行枕，藤花醒酒羹。", "吾詩不堪煮，亦足了吾生。"]'),
('c32d1dee-9c8e-499b-bf35-f7b4daf94f05','山居十首  其二','方岳','宋','宋诗','song-poetry','','[]','我愛山居好，紅稠處處花。',48,'全唐诗/poet.song.212000.json','["我愛山居好，紅稠處處花。", "雲粘居士屩，藤覆野人家。", "入饌春燒筍，分燈夜作茶。", "無人共襟抱，烟雨話桑麻。"]'),
('7af477df-504b-4b3e-ba97-94112839942c','山居十首  其三','方岳','宋','宋诗','song-poetry','','[]','我愛山居好，閒吟樹倚身。',48,'全唐诗/poet.song.212000.json','["我愛山居好，閒吟樹倚身。", "田園無事日，天地自由人。", "野竹窮三逕，山苗草八珍。", "醉歸渾不記，黄犢自知津。"]'),
('76c371c5-4684-4b7c-b657-5383d1d9db8b','山居十首  其四','方岳','宋','宋诗','song-poetry','','[]','我愛山居好，林霏曉未開。',48,'全唐诗/poet.song.212000.json','["我愛山居好，林霏曉未開。", "龍蛇松薜荔，虎兕石莓苔。", "太古雲猶在，常時雨亦來。", "暝巖眠處冷，不記到蓬萊。"]'),
('90fe5f1c-9e0e-47e2-90f1-4cab43f0e52b','山居十首  其五','方岳','宋','宋诗','song-poetry','','[]','我愛山居好，堆豗忽坐忘。',48,'全唐诗/poet.song.212000.json','["我愛山居好，堆豗忽坐忘。", "草塘銀潑剌，庵戶鐵琅璫。", "只道雲藏塢，那知市隔牆。", "人嫌吾寂寞，吾亦笑人忙。"]'),
('dfbc0932-a302-40ad-a45e-c0c302b97eed','山居十首  其六','方岳','宋','宋诗','song-poetry','','[]','我愛山居好，躋攀繚暝烟。',48,'全唐诗/poet.song.212000.json','["我愛山居好，躋攀繚暝烟。", "偃松低可坐，橫石劣容眠。", "菊徑重陽酒，梅花雪後天。", "一筇吾事足，與世自無緣。"]'),
('d4711b40-a004-41a0-8e28-63fc761e3674','山居十首  其七','方岳','宋','宋诗','song-poetry','','[]','我愛山居好，乾坤自一丘。',48,'全唐诗/poet.song.212000.json','["我愛山居好，乾坤自一丘。", "牡丹新富貴，楊柳舊風流。", "婦喜醅新熟，兒誇麥有秋。", "人生行樂耳，身外更何求。"]'),
('aa1d40ef-f268-49da-9cd8-5ca20fc494b3','山居十首  其八','方岳','宋','宋诗','song-poetry','','[]','我愛山居好，新篁綠上竿。',48,'全唐诗/poet.song.212000.json','["我愛山居好，新篁綠上竿。", "草蕃侵路狹，地闊占雲寬。", "山響棋聲濕，堂深樹影寒。", "柴門底須掩，非意不相干。"]'),
('c45bfe80-9469-4552-be30-4861f03da6fe','山居十首  其九','方岳','宋','宋诗','song-poetry','','[]','我愛山居好，遥岑碧四圍。',48,'全唐诗/poet.song.212000.json','["我愛山居好，遥岑碧四圍。", "雲沈平釣石，草蔓亞樵扉。", "野水喧姑惡，春陰怨姊歸。", "坐來還失笑，吾道是耶非。"]'),
('fbdd5f0f-7a9f-497f-9be7-c2c87d37fdd7','山居十首  其一○','方岳','宋','宋诗','song-poetry','','[]','我愛山居好，畦蔬手自耘。',48,'全唐诗/poet.song.212000.json','["我愛山居好，畦蔬手自耘。", "鳥聲穿戶過，鶴唳隔村聞。", "石溜渾如雨，溪船盡是雲。", "煩君謝逋客，不用北山文。"]'),
('729f298a-7a48-406a-93f3-11c5fc24eed7','意行','方岳','宋','宋诗','song-poetry','','[]','小彴通幽徑，半山生夕陰。',48,'全唐诗/poet.song.212000.json','["小彴通幽徑，半山生夕陰。", "鳥聲花外急，春意柳邊深。", "人事雲無定，吾生日已沈。", "不知松作麽，也換去年心。"]'),
('087d5646-befa-4d32-bf51-52e6d0e1d9ab','送章監丞守廣信  其一','方岳','宋','宋诗','song-poetry','','[]','近世無佳郡，中朝有此公。',48,'全唐诗/poet.song.212000.json','["近世無佳郡，中朝有此公。", "再三疑壞證，第一是貪風。", "野雪深耕耒，春苔蝕缿筒。", "龔黄只如此，爲問玉山翁。"]'),
('d97e7e48-f5af-4bb1-8461-9b45da07f71f','送章監丞守廣信  其二','方岳','宋','宋诗','song-poetry','','[]','勇去何爲者，尋盟少可人。',48,'全唐诗/poet.song.212000.json','["勇去何爲者，尋盟少可人。", "雁聲江國曉，梅蕊雪籬春。", "同舍誰如子，爲州獨有親。", "月巖吟處碧，物物是吾仁。"]'),
('05702ed6-9feb-48c5-a08d-bc01f8f76c14','社日次韻  其一','方岳','宋','宋诗','song-poetry','','[]','社日神林鼓，豐年處處祈。',48,'全唐诗/poet.song.212000.json','["社日神林鼓，豐年處處祈。", "水痕深浸穀，野燒暖生薇。", "農務相尋急，吾詩不療饑。", "夜長閒扣角，亦喜飯牛肥。"]'),
('65979f41-e016-47da-a401-6432ecb4e12d','社日次韻  其二','方岳','宋','宋诗','song-poetry','','[]','邂逅治聾酒，春風免破除。',48,'全唐诗/poet.song.212000.json','["邂逅治聾酒，春風免破除。", "燕來雙鬢雪，花覆一床書。", "野碓生茨草，山盂飽飯蔬。", "宰平無此手，自覺老懷紓。"]'),
('9a9b1eb0-db7c-4512-bfba-e8d6bd6462ed','五月初四大水','方岳','宋','宋诗','song-poetry','','[]','山雲一夜雨，溪漲疾於飛。',48,'全唐诗/poet.song.212000.json','["山雲一夜雨，溪漲疾於飛。", "小市通爲壑，幽居半及扉。", "木披龍有迹，牆斷鶴無歸。", "書帙方狼籍，誰看舊釣磯。"]'),
('9ea7d5b9-1e6e-4d9e-9e3d-14d1f868026b','不寐  其一','方岳','宋','宋诗','song-poetry','','[]','不寐何爲者，幽居事更稠。',48,'全唐诗/poet.song.212000.json','["不寐何爲者，幽居事更稠。", "怯風思鶴冷，聞雨爲花愁。", "草合妨遊屐，沙崩壓釣舟。", "春蓑故無恙，欹枕數更籌。"]'),
('7df3b871-111c-469d-b4d0-7228bd7b9342','不寐  其二','方岳','宋','宋诗','song-poetry','','[]','不寐何爲者，閒人最號忙。',48,'全唐诗/poet.song.212000.json','["不寐何爲者，閒人最號忙。", "釀方傳得法，詩未足成章。", "藥草霜多損，寒蔬雨半荒。", "幸無天下責，夔卨在巖廊。"]'),
('84848f46-45f2-46da-a99c-a0672ce9f2e0','次韻林同年','方岳','宋','宋诗','song-poetry','','[]','歲月半行李，與君荆蔞間。',48,'全唐诗/poet.song.212000.json','["歲月半行李，與君荆蔞間。", "十年場屋夢，何日道家山。", "征棹江千里，雩壇月一間。", "豈無經濟意，生世政多囏。"]'),
('90ee0a1b-5b0d-4d40-a1d4-344813bee3e2','次韻話別','方岳','宋','宋诗','song-poetry','','[]','一雨桐江滑，佳哉月一篷。',48,'全唐诗/poet.song.212000.json','["一雨桐江滑，佳哉月一篷。", "歸猶慙怨鶴，悔不蚤冥鴻。", "涉世書無用，尋山酒有功。", "諸人如見問，貧耳却非窮。"]'),
('89f6603c-3f61-4675-98c5-8506c1552072','程伯茂尊公挽詩','方岳','宋','宋诗','song-poetry','','[]','雨昏先友記，猶復有斯人。',48,'全唐诗/poet.song.212000.json','["雨昏先友記，猶復有斯人。", "周易相傳授，唐衫自隠淪。", "翳桑秋廩共，結草夜臺春。", "爲酹月塘月，何年琢石麟。"]'),
('d5b655b2-9e12-4dce-a2ec-95c9af9ffe05','知瑞州羅大夫挽詩','方岳','宋','宋诗','song-poetry','','[]','汙俗狂瀾倒，公平今獨賢。',48,'全唐诗/poet.song.212000.json','["汙俗狂瀾倒，公平今獨賢。", "折腰慙爲米，絕口不言錢。", "筆橐名臣後，簞瓢素士先。", "只消廉吏字，題作墓門鎸。"]'),
('ef5679a1-c079-4079-b9eb-8a7274d4fcee','用趙尉韻寄題約山樓','方岳','宋','宋诗','song-poetry','','[]','可人期不至，樓外有佳山。',48,'全唐诗/poet.song.212000.json','["可人期不至，樓外有佳山。", "幾點寒林畫，一簾秋水環。", "只煩詩五字，相與月三間。", "貴賤交情薄，何妨自往還。"]'),
('be2bf5bf-ba31-41d9-88b1-2734cbf9fe49','阻風','方岳','宋','宋诗','song-poetry','','[]','佳處何妨住，江晴倚落暉。',48,'全唐诗/poet.song.212000.json','["佳處何妨住，江晴倚落暉。", "野船穿樹過，沙鳥带雲飛。", "寺有唐碑古，山羞漢鼎非。", "長安多過客，留墨滿苔磯。"]'),
('7853c720-585a-4ae9-a194-1db28be9a394','知郡陳告院挽詩','方岳','宋','宋诗','song-poetry','','[]','舊隠真僊宅，論詩得老干。',48,'全唐诗/poet.song.212000.json','["舊隠真僊宅，論詩得老干。", "雲沈海屋古，書擁雪燈殘。", "一棹橫秋色，九華生暮寒。", "空餘青眼在，肯作故人看。"]'),
('eb631992-e97f-4f00-a5db-891e8e88cc35','次韻酬戴式之','方岳','宋','宋诗','song-poetry','','[]','山房秋蘚滑，吾亦爲詩來。',48,'全唐诗/poet.song.212000.json','["山房秋蘚滑，吾亦爲詩來。", "家遠雁初到，邊寒菊未開。", "貧知心事古，老覺鬢毛催。", "能共清談否，呼童急洗杯。"]'),
('f4f115fa-7765-43f2-9084-5a1c39b47eaf','再用韻約式之','方岳','宋','宋诗','song-poetry','','[]','已掃秋庭月，蹇馿來未來。',48,'全唐诗/poet.song.212000.json','["已掃秋庭月，蹇馿來未來。", "一官連我俗，雙眼向誰開。", "書癖工爲祟，詩窮不受催。", "是中惟酒可，到手莫停杯。"]'),
('29366cc4-e795-47dd-b297-67954cde85ee','寄姪','方岳','宋','宋诗','song-poetry','','[]','爾亦爲貧驅，窗間硯欲枯。',48,'全唐诗/poet.song.212000.json','["爾亦爲貧驅，窗間硯欲枯。", "自從村墅別，曾到陝山無。", "寒圃應肥菜，秋霖怕損租。", "有書供夜讀，時一喚吾雛。"]'),
('761638c2-26c4-4e9a-a7de-58a2de507772','送呂提幹併簡謝泉','方岳','宋','宋诗','song-poetry','','[]','山雲一夜雨，穩放過閶船。',48,'全唐诗/poet.song.212000.json','["山雲一夜雨，穩放過閶船。", "坑發寧遺壙，民貧不爲錢。", "范碑秋寺古，楚觀暮江前。", "寄謝東山老，靈砂併欲僊。"]'),
('0c82baa2-db9e-4078-934b-13ab51dbcc95','送劉子範倅宜春','方岳','宋','宋诗','song-poetry','','[]','一念到吾親，人間萬事輕。',48,'全唐诗/poet.song.212000.json','["一念到吾親，人間萬事輕。", "鄰州纔半刺，行李只諸生。", "問路重陽雨，迎家兩日程。", "笑談燈火夜，邊雁自秋聲。"]'),
('844c1c45-8ec5-42b4-842d-de56024608c2','送應武諭倅廬陵','方岳','宋','宋诗','song-poetry','','[]','乞倅廬陵郡，予爲第一人。',48,'全唐诗/poet.song.212000.json','["乞倅廬陵郡，予爲第一人。", "天慳終未肯，人好自相親。", "諸老詩書在，平園草木春。", "鷗朋嘲薄分，山屐蝕京塵。"]'),
('a7621d72-f81b-40a6-ad78-971f5d556282','敬亭道中','方岳','宋','宋诗','song-poetry','','[]','小謝曾臨郡，山應自識詩。',48,'全唐诗/poet.song.212000.json','["小謝曾臨郡，山應自識詩。", "空餘春草夢，無復敬亭碑。", "暝色如相覓，秋雲不受吹。", "買魚尋宿處，烟水有茅茨。"]'),
('5d1f7d15-af30-4caf-9333-72efb1fb2ac6','宿奉聖寺下','方岳','宋','宋诗','song-poetry','','[]','幽事隨人撰，茲行亦屢逢。',48,'全唐诗/poet.song.212000.json','["幽事隨人撰，茲行亦屢逢。", "飯多依釣艇，宿喜近僧鐘。", "野水連秋暝，溪烟急晚舂。", "誠齋題石老，細讀得從容。"]'),
('fb5f6d53-90da-4d84-8e57-5a794560df20','舟次當塗','方岳','宋','宋诗','song-poetry','','[]','一似餘杭路，寒洲半是蘆。',48,'全唐诗/poet.song.212000.json','["一似餘杭路，寒洲半是蘆。", "客依秋泊岸，漁带晚收罛。", "遠樹齊於薺，平蕪雜以鳬。", "可憐沙上月，相見又當塗。"]'),
('733e9e21-4c49-4471-b162-e6a4eddbe7ca','七夕鄭文振席上姬有楚雲者爲作三弄','方岳','宋','宋诗','song-poetry','','[]','帝子經年別，秋風遠客情。',48,'全唐诗/poet.song.212000.json','["帝子經年別，秋風遠客情。", "斷雲含宿雨，古木落寒聲。", "河漢低逾潤，江潮夜未平。", "巫雲莫吹笛，吾意正凄清。"]'),
('1de1db2b-f292-44c0-bd2b-61ca29b58dd2','次韻王尉','方岳','宋','宋诗','song-poetry','','[]','雪屋誰堪語，惟愁鶴共居。',48,'全唐诗/poet.song.212000.json','["雪屋誰堪語，惟愁鶴共居。", "夢靈山有分，門冷客無書。", "詩豈於人癖，吾元與世疎。", "窮知書作祟，牽率費春鋤。"]'),
('fb2d74ff-6aa1-48f9-b2cf-d1098e115ee4','寄湯卿','方岳','宋','宋诗','song-poetry','','[]','書冊依官屋，何如自在身。',48,'全唐诗/poet.song.212000.json','["書冊依官屋，何如自在身。", "且無山得看，猶有竹相鄰。", "性野回書懶，詩癡易藁頻。", "便歸吾已俗，往往白鷗嗔。"]'),
('9c85e5f7-6731-4c9e-824f-772d26062171','舟次嚴陵  其一','方岳','宋','宋诗','song-poetry','','[]','人語山相應，舟行岸自移。',48,'全唐诗/poet.song.212000.json','["人語山相應，舟行岸自移。", "魚因寒越雋，鷺到晚猶饑。", "歲盡難爲客，江晴易得詩。", "渺予烟水闊，何以此行爲。"]'),
('eb5d2ae7-7b04-4d98-832e-e808e865dd7c','舟次嚴陵  其二','方岳','宋','宋诗','song-poetry','','[]','與雁分洲宿，連雲做夢清。',48,'全唐诗/poet.song.212000.json','["與雁分洲宿，連雲做夢清。", "江風人事老，夜雨客心驚。", "潮急仍吞瀨，更寒不過城。", "子陵吾所韙，簑外底須名。"]'),
('616e30f8-e3cd-4a02-88bb-7275366b05da','送別史僉','方岳','宋','宋诗','song-poetry','','[]','二月寒如此，君胡不少留。',48,'全唐诗/poet.song.212000.json','["二月寒如此，君胡不少留。", "夕陽隨水去，春草泥人愁。", "江上三年別，詩邊兩鬢秋。", "折腰貧尚爾，天地一扁舟。"]'),
('90eb3170-8622-44a9-9b62-e1a060c5002b','熱甚有懷山間','方岳','宋','宋诗','song-poetry','','[]','終是山間別，寒泉在脚邊。',48,'全唐诗/poet.song.212000.json','["終是山間別，寒泉在脚邊。", "戲魚爭美蔭，啼鳥破佳眠。", "山寂夜如水，僧閒日抵年。", "欲來來未得，戽斗救枯田。"]'),
('4581f74f-ed43-4972-9c89-f722489c8fba','寄魯山兄','方岳','宋','宋诗','song-poetry','','[]','摇落山城暮，行人返照邊。',48,'全唐诗/poet.song.212000.json','["摇落山城暮，行人返照邊。", "亂蟬鳴古柳，獨鶴下遥川。", "秋事無多日，寒花又一年。", "故應深夜雨，重憶對床眠。"]'),
('609c1656-efc1-4996-89aa-4b3fe8d6baae','次韻王尉天寧晚飯','方岳','宋','宋诗','song-poetry','','[]','借得山房住，清溪带晚林。',48,'全唐诗/poet.song.212000.json','["借得山房住，清溪带晚林。", "雲應隨鶴宿，詩亦對僧吟。", "杯滑知能雋，窗深苦易陰。", "劇知歸思浩，吾亦識琴心。"]'),
('37191c9a-29fe-45c1-be9d-47688feb043f','煮茶','方岳','宋','宋诗','song-poetry','','[]','瀑近春風濕，松花滿石壇。',48,'全唐诗/poet.song.212000.json','["瀑近春風濕，松花滿石壇。", "不知茶鼎沸，但覺雨聲寒。", "山好僧吟久，雲深鶴睡寬。", "詩成不須寫，怕有俗人看。"]'),
('98b96bc7-e7d9-4507-a60c-107834bb362b','猿','方岳','宋','宋诗','song-poetry','','[]','三峽巴江水，何年離爾羣。',48,'全唐诗/poet.song.212000.json','["三峽巴江水，何年離爾羣。", "艱難俱未免，清切不堪聞。", "羈旅仍春浦，愁懷况暮雲。", "尚思靈澗冷，蘿蔦月紛紛。"]'),
('dc938365-2ad8-420d-81bb-a21125aa9ae7','解榻','方岳','宋','宋诗','song-poetry','','[]','解榻留雲宿，山居事事幽。',48,'全唐诗/poet.song.212000.json','["解榻留雲宿，山居事事幽。", "長貧吾道在，多病此生浮。", "野色連溪暝，蟲聲滿院秋。", "那知一丁字，蚤白十年頭。"]'),
('d60fd658-e3ad-452b-b6dd-8ff5fefc485a','聽雨','方岳','宋','宋诗','song-poetry','','[]','竹齋眠聽雨，夢裏長青苔。',48,'全唐诗/poet.song.212000.json','["竹齋眠聽雨，夢裏長青苔。", "門寂山相對，身閒鳥不猜。", "客應嫌酒盡，花却爲詩開。", "莫下簾尤好，恐妨雲徃來。"]'),
('c0e7d01b-054c-430a-a4a4-811c5359e10a','初秋','方岳','宋','宋诗','song-poetry','','[]','殘暑何時退，秋風日夜生。',48,'全唐诗/poet.song.212000.json','["殘暑何時退，秋風日夜生。", "已嫌湘簟冷，稍覺楚天清。", "山路晴猶濕，星河夜自明。", "時聞梧葉落，一似打門聲。"]'),
('29bb7ed6-82e9-43a8-a643-c7035ddc3d3b','晚興','方岳','宋','宋诗','song-poetry','','[]','山淡長疑雨，看山自撚髭。',48,'全唐诗/poet.song.212000.json','["山淡長疑雨，看山自撚髭。", "暝雲延晚逕，秋蔓亞疎籬。", "院靜凉於水，人閒瘦似詩。", "移床眠對竹，莫與俗人知。"]'),
('c6364524-e83e-4211-868a-4fb3474d3a1d','送子用弟遊學番昜','方岳','宋','宋诗','song-poetry','','[]','頓覺溪流滑，番湖草欲春。',48,'全唐诗/poet.song.212000.json','["頓覺溪流滑，番湖草欲春。", "船輕携硯易，家近寄書頻。", "山雨同離別，寒窗自寵珍。", "但於燈火夜，報子倚門親。"]'),
('649268af-7645-4754-80cc-9445ee51fb16','唐律十首  其一','方岳','宋','宋诗','song-poetry','','[]','雲木上蒼冥，行藏只草亭。',48,'全唐诗/poet.song.212000.json','["雲木上蒼冥，行藏只草亭。", "雁隨秋到早，山入市來青。", "投老餘漁具，能詩例鶴形。", "髮根風露入，肺渴喜初醒。"]'),
('1feb4a3e-fba3-49dc-947b-684721e211be','唐律十首  其二','方岳','宋','宋诗','song-poetry','','[]','盡日此徘徊，青粘兩屨苔。',48,'全唐诗/poet.song.212000.json','["盡日此徘徊，青粘兩屨苔。", "鳥聲穿戶去，暝色過溪來。", "象齒劙鞭茁，銀刀罾繪材。", "空山人自老，醉眼向誰開。"]'),
('e0f53038-433c-4701-926c-af9351b7af8d','唐律十首  其三','方岳','宋','宋诗','song-poetry','','[]','有客共攢眉，蠶叢事可悲。',48,'全唐诗/poet.song.212000.json','["有客共攢眉，蠶叢事可悲。", "渡瀘諸葛表，哀汴老韓詩。", "誰又青冥鉞，吾方白接䍦。", "神謨自堅定，豺虎莫恫疑。"]'),
('4c209748-1870-46f1-a248-869832f81b56','唐律十首  其四','方岳','宋','宋诗','song-poetry','','[]','松露滴深幽，山寒草逕秋。',48,'全唐诗/poet.song.212000.json','["松露滴深幽，山寒草逕秋。", "蔓藤行伏兔，野竹上牽牛。", "日月雙車轂，乾坤一傳郵。", "功名成底事，何苦覓封侯。"]'),
('2b6af7f6-1709-4b25-b1fc-c77c3e59fae7','唐律十首  其五','方岳','宋','宋诗','song-poetry','','[]','捲雨對遥岑，詩寒不自禁。',48,'全唐诗/poet.song.212000.json','["捲雨對遥岑，詩寒不自禁。", "猿猱三徑小，虎豹九關深。", "道眼虛空界，閒身自在心。", "荷鋤今亦倦，年與病相尋。"]'),
('222bf188-2968-4193-b02b-7122d339ba1d','唐律十首  其六','方岳','宋','宋诗','song-poetry','','[]','老去脚猶輕，吟邊不杖行。',48,'全唐诗/poet.song.212000.json','["老去脚猶輕，吟邊不杖行。", "孤亭深野色，高木易秋聲。", "歲事纔中熟，山居亦太平。", "不辭遭泥飲，謹勿殺能鳴。"]'),
('e37bce54-2305-414e-afc3-3eb3bcf422a8','唐律十首  其七','方岳','宋','宋诗','song-poetry','','[]','經月魃爲妖，連宵雨似潮。',48,'全唐诗/poet.song.212000.json','["經月魃爲妖，連宵雨似潮。", "山田禾側耳，野漲樹平腰。", "古語天難做，民生日不聊。", "忍饑吾亦慣，古色一簞瓢。"]'),
('ec2dcb55-142a-47fe-801d-6042391089d7','唐律十首  其八','方岳','宋','宋诗','song-poetry','','[]','寂寞斷過從，行山又一重。',48,'全唐诗/poet.song.212000.json','["寂寞斷過從，行山又一重。", "烟村秋色畫，茅屋夕陽舂。", "得句多題竹，觀書半倚松。", "心閒身已老，悔不早歸農。"]'),
('e8c64a66-1eb7-4ab4-8320-3153c4c87024','唐律十首  其九','方岳','宋','宋诗','song-poetry','','[]','谷口豈其卿，胡然朝市爭。',48,'全唐诗/poet.song.212000.json','["谷口豈其卿，胡然朝市爭。", "遠山長晚色，幽鳥乍春聲。", "老覺人情薄，閒於世累輕。", "早紅香可飯，何必又魚羹。"]'),
('5e3f3876-b03b-46f5-b854-4d7d71f39a42','唐律十首  其一○','方岳','宋','宋诗','song-poetry','','[]','吾亦愛吾貧，樵山採墮薪。',48,'全唐诗/poet.song.212000.json','["吾亦愛吾貧，樵山採墮薪。", "百年雙短鬢，九職一閒民。", "秋蔓茶僧老，春泓酒母淳。", "兩生誰可致，此外不關身。"]'),
('c53f8e2a-268b-43e0-a70d-6c8f599ce858','挽彭制機  其一','方岳','宋','宋诗','song-poetry','','[]','場屋崢嶸氣，雖平豈易干。',48,'全唐诗/poet.song.212000.json','["場屋崢嶸氣，雖平豈易干。", "江湖雙鬢古，師友一燈寒。", "戍柝猶傳檄，漁烟自釣竿。", "極知書有種，吾道未凋殘。"]'),
('c7d863b0-0aca-4d48-8221-298c0355ed10','挽彭制機  其二','方岳','宋','宋诗','song-poetry','','[]','山中亦云樂，蔬甲手耘芟。',48,'全唐诗/poet.song.212000.json','["山中亦云樂，蔬甲手耘芟。", "面熟鳥窺戶，眼生雲穴巖。", "樹蟠根可坐，路礙石休劖。", "每笑陶弘景，猶將隠結銜。"]'),
('1cd93df0-21de-4b05-ac0f-9cb01c430557','簡杜子昕節邠','方岳','宋','宋诗','song-poetry','','[]','買屋湖邊住，湖光入酒巵。',48,'全唐诗/poet.song.212000.json','["買屋湖邊住，湖光入酒巵。", "向來多說劍，老去只耽詩。", "時序寬衣带，年華上鬢絲。", "肯收湖海氣，了事覺兒癡。"]'),
('e82ce517-9ef1-4352-9262-6b9eb931121a','出關','方岳','宋','宋诗','song-poetry','','[]','江雨正冥冥，江鷗聚晚汀。',48,'全唐诗/poet.song.212000.json','["江雨正冥冥，江鷗聚晚汀。", "雲深城闕麗，潮落海門青。", "宇宙雙蓬鬢，江湖幾驛亭。", "不須關卒邏，吾亦厭銅腥。"]'),
('98b7fc73-6717-41a8-a76e-99033dad95ee','泊歙浦','方岳','宋','宋诗','song-poetry','','[]','此路難爲別，丹楓似去年。',48,'全唐诗/poet.song.212000.json','["此路難爲別，丹楓似去年。", "人行秋色裏，雁落客愁邊。", "霜月欹寒渚，江聲驚夜船。", "孤城吹角處，獨立渺風烟。"]'),
('22c16fce-c22a-4a71-80b8-1a66eeb6b578','重陽','方岳','宋','宋诗','song-poetry','','[]','古岸維舟夜，蕭蕭秋葉丹。',48,'全唐诗/poet.song.212000.json','["古岸維舟夜，蕭蕭秋葉丹。", "野烟連竹暗，江雨灑燈寒。", "亦喜重陽健，誰知行路難。", "吾親應念我，更把菊花看。"]'),
('d30b6d2f-ff93-4e16-999b-b7fbf2c2ef8e','九日','方岳','宋','宋诗','song-poetry','','[]','逢人提菊賣，方省是重陽。',48,'全唐诗/poet.song.212000.json','["逢人提菊賣，方省是重陽。", "山曉雨初霽，江秋樹亦凉。", "年華猶故我，烽火更殊鄉。", "有客那無酒，令人憶草堂。"]'),
('27a7c9c3-ae1a-43a5-97f2-101f72e4eeee','秋曉登山','方岳','宋','宋诗','song-poetry','','[]','發興在丘林，其如老見尋。',48,'全唐诗/poet.song.212000.json','["發興在丘林，其如老見尋。", "身餘持蟹手，脚負看山心。", "秋色蒼厓暝，曉籬黄葉深。", "惟應負苓者，來往古松陰。"]'),
('b96eb1a7-18d3-4612-9751-6bd4b878a056','蘭溪晚泊','方岳','宋','宋诗','song-poetry','','[]','岸岸蘆花白，空江多月明。',48,'全唐诗/poet.song.212000.json','["岸岸蘆花白，空江多月明。", "一簾秋色老，千里暮雲平。", "寒入霜前韭，香傳雨後橙。", "煩詩題品看，此酒舊知名。"]'),
('6c5f2f5b-d932-4056-8361-841028e26a1c','八詠樓','方岳','宋','宋诗','song-poetry','','[]','郡古低臨水，城荒早閉門。',48,'全唐诗/poet.song.212000.json','["郡古低臨水，城荒早閉門。", "岸沙分路細，江南带雲昏。", "山豈緣詩瘦，樓應厭市喧。", "前朝碑尚在，半已蝕苔痕。"]'),
('f1a44e70-937e-47ba-aafa-b4c5acdc8374','次韻趙尉','方岳','宋','宋诗','song-poetry','','[]','括山隨處好，况復有詩人。',48,'全唐诗/poet.song.212000.json','["括山隨處好，况復有詩人。", "粘壁多詩藁，看山少訟塵。", "夜寒琴伴月，香冷硯生春。", "鶴亦能留客，敲門不厭頻。"]'),
('ef4288bd-f5fb-4697-a204-fc2717168b06','次韻陳湯卿  其一','方岳','宋','宋诗','song-poetry','','[]','括蒼烟雨頂，客木晚巑岏。',48,'全唐诗/poet.song.212000.json','["括蒼烟雨頂，客木晚巑岏。", "家遠書難到，雲深夢亦寒。", "僧邀携茗試，客許借詩看。", "琴冷梅花月，何時爲一彈。"]'),
('ff61bdd8-f422-4d95-b4dd-bb1792445ae4','次韻陳湯卿  其二','方岳','宋','宋诗','song-poetry','','[]','野逕漁樵共，霜寒江上村。',48,'全唐诗/poet.song.212000.json','["野逕漁樵共，霜寒江上村。", "亂山橫紫翠，孤笛送黄昏。", "滿壁題詩暗，連牆貰酒渾。", "往來今已熟，稚子又譍門。"]'),
('ce652a65-a556-46e9-909f-b0c28731a370','次梁倅錄囚上饒','方岳','宋','宋诗','song-poetry','','[]','此老清如許，寧求使節知。',48,'全唐诗/poet.song.212000.json','["此老清如許，寧求使節知。", "檄分風憲重，山到月巖奇。", "秋色深宜雨，寒花併入詩。", "聖朝本仁厚，鼠輩亦吾兒。"]'),
('83718c84-f85c-42a7-bfa2-a937525a8fb0','陳帳管尊公挽詩','方岳','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','不獨於書癖，論邊語亦奇。',48,'全唐诗/poet.song.212000.json','["不獨於書癖，論邊語亦奇。", "丘園身竟老，場屋世誰知。", "客下陳蕃榻，人傳竇諫碑。", "九華山翠外，煙草正離離。"]'),
('d85c3046-89ff-441f-aa30-a91507381075','道中連雨  其一','方岳','宋','宋诗','song-poetry','','[]','老屋村舂急，歸鴉半暝煙。',48,'全唐诗/poet.song.212000.json','["老屋村舂急，歸鴉半暝煙。", "斷厓留宿雨，野水沒春田。", "昨夢山須記，幽情鳥不傳。", "也知晴更好，草木已爭妍。"]'),
('66b22ff4-46c4-4a2e-80d4-38454beab9dd','道中連雨  其二','方岳','宋','宋诗','song-poetry','','[]','蚤晏逢人問，荒村店亦稀。',48,'全唐诗/poet.song.212000.json','["蚤晏逢人問，荒村店亦稀。", "竹輿穿雨過，沙鳥带雲飛。", "野渡疑無樹，春山儘有薇。", "不緣詩是伴，誰與倚荆扉。"]'),
('d3852e11-7433-45ae-baf5-2dbf1a75f9fa','道中連雨  其三','方岳','宋','宋诗','song-poetry','','[]','塵蝕貂裘敝，吾生奈爾何。',48,'全唐诗/poet.song.212000.json','["塵蝕貂裘敝，吾生奈爾何。", "雷聲春蟄怒，山意暮寒多。", "窮不彈長鋏，歸應負短簑。", "自知機事淺，或可共鷗波。"]'),
('e0736a12-36cb-4884-9390-511dc6db4d55','次韻汪少卿贈別','方岳','宋','宋诗','song-poetry','','[]','一詩傳戟外，春亦肯隨行。',48,'全唐诗/poet.song.212000.json','["一詩傳戟外，春亦肯隨行。", "老不論圭瓚，寒於嚼水晶。", "夢驚池草合，香泛墨花輕。", "立盡沙頭月，鷗清睡不成。"]'),
('0ebc990f-8b20-4c27-93cb-f723f72ffad1','次韻酬其乂','方岳','宋','宋诗','song-poetry','','[]','心事一鷗輕，郵籤夜卜程。',48,'全唐诗/poet.song.212000.json','["心事一鷗輕，郵籤夜卜程。", "春寒眼對雨，別久語連明。", "硯有詩能秀，山於夢亦清。", "歙溪多老石，一一待題名。"]'),
('d1d2de01-f684-4065-9c0e-b67981280cec','再用汪少卿韻','方岳','宋','宋诗','song-poetry','','[]','畢竟春晴好，楊花也送行。',48,'全唐诗/poet.song.212000.json','["畢竟春晴好，楊花也送行。", "驛程寒冉冉，江樹曉晶晶。", "水長船能駛，詩多擔轉輕。", "江湖吾倦矣，茅屋幾時成。"]'),
('bc9c4855-2f4c-4209-a07d-2e7211d37a5e','次韻別元可','方岳','宋','宋诗','song-poetry','','[]','帆带春風夢，鷗知遠客心。',48,'全唐诗/poet.song.212000.json','["帆带春風夢，鷗知遠客心。", "暮愁隨雨做，逸興與江深。", "書不厭頻讀，詩須放淡吟。", "絕憐寒食酒，與子不同斟。"]'),
('27bbf00f-029f-459c-9f9e-a6173dea1e59','次韻趙尉','方岳','宋','宋诗','song-poetry','','[]','昨過騎馿尉，香深茗一杯。',48,'全唐诗/poet.song.212000.json','["昨過騎馿尉，香深茗一杯。", "杏寒春且住，芹老燕初來。", "山自相知甚，僊今安在哉。", "晚洲分鷺宿，了不受嫌猜。"]'),
('081e21a9-0aca-45a4-b46d-6ab5f50a174c','送別薛丞  其一','方岳','宋','宋诗','song-poetry','','[]','肯爲祁山住，晴浮草木春。',48,'全唐诗/poet.song.212000.json','["肯爲祁山住，晴浮草木春。", "溪晴隨硯轉，心遠與鷗親。", "幾佐弦歌舊，寧矜硎刃新。", "蕭規元好在，傳語憇棠人。"]'),
('0015aaed-c116-4502-8370-7a07a1a99d98','送別薛丞  其二','方岳','宋','宋诗','song-poetry','','[]','題遍南牆玉，與春相伴歸。',48,'全唐诗/poet.song.212000.json','["題遍南牆玉，與春相伴歸。", "花明晴岸闊，帆轉暮江肥。", "鵑老催紅藥，雲香近紫微。", "檣竿兩燕子，也带笑聲飛。"]'),
('0648d308-978a-41f0-b27c-105508e56bd7','灼艾','方岳','宋','宋诗','song-poetry','','[]','人生不滿百，憂患况中年。',48,'全唐诗/poet.song.212000.json','["人生不滿百，憂患况中年。", "藜莧工爲祟，參苓那得錢。", "不虞波及晉，聊復火攻燕。", "一笑遭秦厄，殘書累腹便。"]'),
('b9dc1de4-5fb9-47dc-beab-e3c9cfe0fee7','次韻程兄見寄','方岳','宋','宋诗','song-poetry','','[]','舊日曾來處，廳寒雲月閒。',48,'全唐诗/poet.song.212000.json','["舊日曾來處，廳寒雲月閒。", "坐忘無局務，起晏不朝班。", "苔竹關幽事，湖山怪老顔。", "一生憂治世，今轉覺多艱。"]'),
('43993374-d8af-4de2-bae9-c2e0f30a1049','被盜','方岳','宋','宋诗','song-poetry','','[]','鼠輩真成誤，吾墉底用穿。',48,'全唐诗/poet.song.212000.json','["鼠輩真成誤，吾墉底用穿。", "近詩貧有藁，舊物冷無氈。", "輦路沈秋柝，干掫老禁堧。", "故應萑葦外，薄暮不堪船。"]'),
('849afa0c-ce35-43e2-b0fe-1cf998024de9','山墅  其一','方岳','宋','宋诗','song-poetry','','[]','竹逕裹茅茨，荒烟晚未炊。',48,'全唐诗/poet.song.212000.json','["竹逕裹茅茨，荒烟晚未炊。", "氄禽爭灌木，吠犬守巴籬。", "涉世終於拙，歸田已自遲。", "老親頭白盡，眠雨話吾私。"]'),
('dd747629-31eb-4c47-ac3a-fdf5fdfb1108','山墅  其二','方岳','宋','宋诗','song-poetry','','[]','山沍雪雲低，荒蕪略有蹊。',48,'全唐诗/poet.song.212000.json','["山沍雪雲低，荒蕪略有蹊。", "逢人多說虎，隔塢忽聞雞。", "寒剖蜂房戶，晴分麥町畦。", "邇來神亦健，薄飯厭羹藜。"]'),
('09dc863c-e878-4243-921a-51e3cd986f48','山墅  其三','方岳','宋','宋诗','song-poetry','','[]','且莫嫌窮僻，山居儘自奇。',48,'全唐诗/poet.song.212000.json','["且莫嫌窮僻，山居儘自奇。", "候樵分玉蕈，熏穴得香貍。", "杯雋明冰片，崖寒孕雪芝。", "不遺吾一美，慙爾野人爲。"]'),
('fec460a0-6d6d-4cb3-84b7-d594efe95b8d','山墅  其四','方岳','宋','宋诗','song-poetry','','[]','近况居然野，稱呼只墅民。',48,'全唐诗/poet.song.212000.json','["近况居然野，稱呼只墅民。", "有詩供課最，無債惱比鄰。", "性亦無嫌懶，人多不解貧。", "每過田父宿，吾自認吾真。"]'),
('f4f431d4-5be8-4485-97e2-4d82eef1fa65','山墅  其五','方岳','宋','宋诗','song-poetry','','[]','牛背夕陽暖，沙頭霜葉寒。',48,'全唐诗/poet.song.212000.json','["牛背夕陽暖，沙頭霜葉寒。", "酒生寧可薄，橘老尚多酸。", "友昔幾相賣，山吾素所歡。", "牆陰有茅茨，留得菊花看。"]'),
('57aeac1b-e8ef-4e2e-979b-fde2b89f2c3e','趙尉催築秋崖','方岳','宋','宋诗','song-poetry','','[]','只爾三間屋，吾貧未易云。',48,'全唐诗/poet.song.212000.json','["只爾三間屋，吾貧未易云。", "與山先定謚，有客屢移文。", "竹喜今年活，梅從隔塢聞。", "猶嫌灌園力，多爲讀書分。"]'),
('0561a3da-3c4d-4e3d-929e-291bdb9742d1','送王尉歸覲  其一','方岳','宋','宋诗','song-poetry','','[]','喜有吟詩癖，吾儕得往還。',48,'全唐诗/poet.song.212000.json','["喜有吟詩癖，吾儕得往還。", "客惟依竹語，官只似僧閒。", "夜雨燈誰共，秋厓藁未刪。", "柴門黄葉下，別後正須關。"]'),
('75862a6a-8968-45be-b612-8add0547cffb','送王尉歸覲  其二','方岳','宋','宋诗','song-poetry','','[]','不以登朝急，歸歟有母慈。',48,'全唐诗/poet.song.212000.json','["不以登朝急，歸歟有母慈。", "新炊甘野薺，秋思老江蘺。", "薄宦惟琴在，孤征與月隨。", "幾時湖上去，吾欲報鷗知。"]'),
('0d8f479d-8f4b-410f-832f-e0c0a0f2b5f0','次韻縣圃即事','方岳','宋','宋诗','song-poetry','','[]','鳬鴨能閒暇，相依睡淺波。',48,'全唐诗/poet.song.212000.json','["鳬鴨能閒暇，相依睡淺波。", "海棠經雨過，楊柳受春多。", "未必詩窮在，其如酒病何。", "閉門春草長，吾亦斷經過。"]'),
('d71928b7-0713-414b-ad06-b491493c4e4c','阻雪  其一','方岳','宋','宋诗','song-poetry','','[]','客飯江豚美，仍須滯此留。',48,'全唐诗/poet.song.212000.json','["客飯江豚美，仍須滯此留。", "竹深通酒舍，沙冷歇漁舟。", "專與詩爲地，明將雪作愁。", "此行乘興耳，吾亦儘風猷。"]'),
('95d92413-c114-4004-b9f0-41b574814c70','阻雪  其二','方岳','宋','宋诗','song-poetry','','[]','風烟兩不借，此嶺復南崗。',48,'全唐诗/poet.song.212000.json','["風烟兩不借，此嶺復南崗。", "陰石無霜滑，寒梅未雪香。", "逢山貪看畫，得句不成章。", "月下門須掩，多應說短長。"]'),
('7705c1d5-2b78-4495-8606-107e259390a1','阻雪  其三','方岳','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','猶及乾淳舊，廬山一老儒。',48,'全唐诗/poet.song.212000.json','["猶及乾淳舊，廬山一老儒。", "典墳行楚蜀，科目不臯夔。", "秋迥人何在，江空樹欲無。", "重陽風雨近，誰與束生芻。"]'),
('3bb39592-9858-4c3e-8208-14c7335cc00e','題宋氏小赤壁','方岳','宋','宋诗','song-poetry','','[]','自有梅花賦，何煩苦覓詩。',48,'全唐诗/poet.song.212000.json','["自有梅花賦，何煩苦覓詩。", "鶴能嗔客俗，山亦忌人癡。", "岸斷流春急，峰高吐月遲。", "吾詩不須刻，萬一老坡知。"]'),
('095d5993-7485-4ab7-a5f8-c41b0185445e','題湯郎中玉峽','方岳','宋','宋诗','song-poetry','','[]','平擘蒼厓破，晴空雪溜湍。',48,'全唐诗/poet.song.212000.json','["平擘蒼厓破，晴空雪溜湍。", "雙湫嵐氣重，一派雨聲寒。", "自有雲相伴，只消僧共看。", "括芽春可煮，移鼎對巑岏。"]'),
('5d502919-5374-4462-bf58-4f078de49200','離括日子安湯卿子貫同宿天寧','方岳','宋','宋诗','song-poetry','','[]','數月蒼州住，山猶有故情。',48,'全唐诗/poet.song.212000.json','["數月蒼州住，山猶有故情。", "雨如知去日，詩亦了行程。", "官柳因寒損，僧茶带雪清。", "怕無書信便，一夜語連明。"]'),
('fb0bfc84-8fa1-4d02-b5bb-44a5ecf00916','次嚴陵','方岳','宋','宋诗','song-poetry','','[]','二月寒如此，楊花不受春。',48,'全唐诗/poet.song.212000.json','["二月寒如此，楊花不受春。", "路生尋店早，家近夢歸頻。", "白鳥無塵事，青山自故人。", "幾時茅屋下，卜與爾爲鄰。"]'),
('7517cbd9-1bd0-4574-a1cb-5bd9d72d3264','入歙','方岳','宋','宋诗','song-poetry','','[]','野竹吾鄉路，逢人似故知。',48,'全唐诗/poet.song.212000.json','["野竹吾鄉路，逢人似故知。", "社寒催燕早，夜雨勒花遲。", "草入思連夢，山邀到歙詩。", "客中春一半，煞是負春彜。"]'),
('a133f928-ad9a-4c4c-8e04-eb4616bc4f2e','到家','方岳','宋','宋诗','song-poetry','','[]','路遠都無信，燈花亦未知。',48,'全唐诗/poet.song.212000.json','["路遠都無信，燈花亦未知。", "晴看寒食近，歸及牡丹時。", "親却俱差健，兒猶不解癡。", "在家貧亦好，雪夢幾相思。"]'),
('2e014698-319b-48b7-84a7-f0e84cc0dee8','寄曹雲臺  其一','方岳','宋','宋诗','song-poetry','','[]','尚記梅花否，相看只有君。',48,'全唐诗/poet.song.212000.json','["尚記梅花否，相看只有君。", "肯辜清夜夢，去管華山雲。", "帆到知何日，詩今瘦幾分。", "惟應問安處，曉角月中聞。"]'),
('0a27f8c6-3de0-40c0-a62d-2e1bc0ea16ab','寄曹雲臺  其二','方岳','宋','宋诗','song-poetry','','[]','難得宜春便，經時不報書。',48,'全唐诗/poet.song.212000.json','["難得宜春便，經時不報書。", "雨多花較損，雪盡草頻鋤。", "燈火貧如故，山林拙未除。", "有詩無話處，一向閉門居。"]'),
('133752b7-cc4d-46ea-bc0a-5da8c1f5054d','訪僧','方岳','宋','宋诗','song-poetry','','[]','夏氣仍清美，疎林綠未交。',48,'全唐诗/poet.song.212000.json','["夏氣仍清美，疎林綠未交。", "舊移花亞竹，新乳鳥爭巢。", "池地多宜箭，山寮只盖茅。", "每思分一榻，從客借書抄。"]'),
('8e944ee7-5313-457a-8e3d-e9a5d8c10f1a','次韻王尉致香','方岳','宋','宋诗','song-poetry','','[]','客有知吾癖，能分一雪凉。',48,'全唐诗/poet.song.212000.json','["客有知吾癖，能分一雪凉。", "只將詩意思，自與夢商量。", "竹密雨聲雋，窗深山意長。", "研朱對周易，老鼎亦英揚。"]'),
('453d604f-5e64-4625-97ab-d59bd8556bec','挽懶庵處士','方岳','宋','宋诗','song-poetry','','[]','萬事從吾懶，庵居隠者家。',48,'全唐诗/poet.song.212000.json','["萬事從吾懶，庵居隠者家。", "酒深牽率月，詩辦事治花。", "健犢閒耕具，輕鷗憶釣槎。", "歸來誰晤語，野艇渡寒沙。"]'),
('8d3c2931-c72a-489a-8ceb-975acca72e41','次韻秋崖落成','方岳','宋','宋诗','song-poetry','','[]','高亭著處出奇峰，不枉平生此興濃。',64,'全唐诗/poet.song.212000.json','["高亭著處出奇峰，不枉平生此興濃。", "力士鐺隨狂李白，華陽巾墊郭林宗。", "菊花籬落秋寥廓，山市人家翠疊重。", "病起不論雙足繭，層巔更欲試詩筇。"]');
